"use client";

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus, vs } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { User, AlertCircle, Check, Copy, X, Save, Edit2, RefreshCw, Trash2, Clock, Brain, ChevronDown, ChevronRight, ExternalLink, Languages } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  onTranslate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
}

const CodeBlock = ({ 
  value, 
  language, 
  lang, 
  theme,
  onShowToast 
}: { 
  value: string, 
  language: string, 
  lang: Language, 
  theme: Theme,
  onShowToast: (msg: string, type: 'success' | 'error' | 'info') => void 
}) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    onShowToast(t('action.copied_code', lang), 'success');
    setTimeout(() => setCopied(false), 2000);
  };

  // Determine syntax highlighter style based on app theme
  const isDarkTheme = ['dark', 'twilight', 'panda', 'vscode-dark'].includes(theme);
  const style = isDarkTheme ? vscDarkPlus : vs;

  return (
    <div className="relative my-4 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-[#1e1e1e] group shadow-sm">
      <div className="flex items-center justify-between px-3 py-2 bg-gray-100 dark:bg-[#252526] border-b border-gray-200 dark:border-gray-700">
        <span className="font-mono text-xs text-gray-500 dark:text-gray-400 font-medium">{language || 'text'}</span>
        <button 
          onClick={handleCopy} 
          className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-primary-600 dark:text-gray-400 dark:hover:text-primary-400 transition-colors bg-gray-200/50 dark:bg-gray-700/50 px-2 py-1 rounded"
          aria-label={copied ? t('action.copied_code', lang) : t('action.copy_code', lang)}
        >
          {copied ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
          <span>{copied ? t('action.copied', lang) : t('action.copy', lang)}</span>
        </button>
      </div>
      <div className="overflow-x-auto text-sm">
        <SyntaxHighlighter
          language={language || 'text'}
          style={style}
          customStyle={{
            margin: 0,
            padding: '1rem',
            background: 'transparent',
            fontSize: 'inherit',
          }}
          codeTagProps={{
            style: { fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace' }
          }}
        >
          {value}
        </SyntaxHighlighter>
      </div>
    </div>
  );
};

const AutoResizeTextarea = ({ 
  value, 
  onChange, 
  onKeyDown, 
  fontSize, 
  autoFocus,
  lang 
}: { 
  value: string, 
  onChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void, 
  onKeyDown: (e: React.KeyboardEvent) => void, 
  fontSize: number,
  autoFocus?: boolean,
  lang: Language
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useLayoutEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [value]);

  return (
    <textarea 
      ref={textareaRef}
      value={value} 
      onChange={onChange} 
      onKeyDown={onKeyDown} 
      className="w-full bg-transparent text-inherit rounded-none p-0 outline-none border-none focus:ring-0 resize-none overflow-hidden leading-relaxed font-inherit min-w-[200px] whitespace-normal break-words" 
      rows={1}
      style={{ fontSize: `${fontSize}px` }} 
      autoFocus={autoFocus} 
      aria-label={t('input.edit_message_content', lang)}
    />
  );
};

interface ThoughtBlockProps {
  text: string;
  lang: Language;
}

// Thought Block Component
const ThoughtBlock: React.FC<ThoughtBlockProps> = ({ text, lang }) => {
  const [isOpen, setIsOpen] = useState(false); 

  return (
    <div className="my-3 border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50/50 dark:bg-gray-800/30 overflow-hidden">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center gap-2 px-3 py-2 text-xs font-medium text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
      >
        <Brain className="w-3.5 h-3.5 text-gray-400" />
        <span>{t('label.thought_process', lang)}</span>
        <div className="ml-auto">
            {isOpen ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
        </div>
      </button>
      {isOpen && (
         <div className="px-3 py-2 border-t border-gray-200 dark:border-gray-700 text-xs font-mono text-gray-600 dark:text-gray-400 whitespace-pre-wrap leading-relaxed">
             {text}
         </div>
      )}
    </div>
  );
};

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  onTranslate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility
}) => {
  const [editText, setEditText] = useState(msg.text);

  // Local buffer state for smooth streaming
  const [displayedText, setDisplayedText] = useState(msg.text);
  const targetTextRef = useRef(msg.text);
  const animationRef = useRef<number>(0);

  // VSCode Theme Logic
  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl'; // Wider container (1.33x)

  // Sync target text when prop changes
  useEffect(() => {
    targetTextRef.current = msg.text;

    // If animation is disabled, or not a model message, or editing, sync immediately
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing) {
        setDisplayedText(msg.text);
    }
  }, [msg.text, msg.role, isEditing, smoothAnimation]);

  // Sync edit text when starting to edit
  useEffect(() => {
    if (isEditing) setEditText(msg.text);
  }, [isEditing, msg.text]);

  // Smooth Text Animation Loop
  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;

        // If synchronized, stop updates
        if (current === target) return current;

        // If current is longer than target (e.g. deletion/rewrite), sync immediately
        if (current.length > target.length) return target;

        // Determine speed based on buffer size (catch up logic)
        const diff = target.length - current.length;

        let chunk = 2;
        if (diff > 50) chunk = 5;
        if (diff > 100) chunk = 15;
        if (diff > 500) chunk = 50; 

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);

        return nextText;
      });

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation]);

  // Scroll Synchronization
  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing]);

  // Parse Text for Thoughts
  const { thoughts, content } = useMemo(() => {
    if (msg.role !== Role.MODEL || isEditing) {
        return { thoughts: [], content: displayedText };
    }

    const thinkRegex = /<think>([\s\S]*?)(?:<\/think>|$)/g;
    const extractedThoughts: string[] = [];
    let match;

    while ((match = thinkRegex.exec(displayedText)) !== null) {
        extractedThoughts.push(match[1]);
    }

    const cleanContent = displayedText.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();

    return { thoughts: extractedThoughts, content: cleanContent };
  }, [displayedText, msg.role, isEditing]);


  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== msg.text) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const handleTranslateClick = () => {
    onTranslate(msg.id);
    setConfirmDeleteId(null);
  }

  const getWrappingClass = () => {
    switch (textWrapping) {
      case 'forced': return 'whitespace-pre-wrap break-all';
      case 'auto': return 'whitespace-normal break-words';
      case 'default': default: return 'whitespace-pre-wrap break-words';
    }
  };

  // Dynamic opacity
  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  // Animation class
  const animationClass = smoothAnimation ? 'animate-pop-in' : '';

  const wrapperWidthClass = isEditing 
      ? 'w-full max-w-full' 
      : 'max-w-[95%] md:max-w-[85%]'; // Standard constraint

  // VSCode Themes: No border color
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  // Avatar Visibility Logic
  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {/* Avatar */}
            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            {/* Message Content Wrapper */}
            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                <>
                    {msg.isError ? (
                    <div className="flex items-center gap-2"><AlertCircle className="w-4 h-4" /><span>{msg.text}</span></div>
                    ) : (
                    <div className={`prose prose-sm max-w-none leading-relaxed dark:prose-invert ${getWrappingClass()}`} style={{ fontSize: `${fontSize}px` }}>
                        {/* Render Thought Blocks if present */}
                        {thoughts.length > 0 && (
                            <div className="mb-3 flex flex-col gap-2">
                                {thoughts.map((thought, idx) => (
                                    <ThoughtBlock key={idx} text={thought} lang={language} />
                                ))}
                            </div>
                        )}

                        <ReactMarkdown 
                            remarkPlugins={[remarkGfm, remarkMath]} 
                            rehypePlugins={[rehypeKatex]} 
                            components={{ 
                                code({node, className, children, ...props}) { 
                                    const match = /language-(\w+)/.exec(className || ''); 
                                    const isInline = !match && !String(children).includes('\n'); 

                                    if (isInline) {
                                      return (
                                        <code 
                                          className="bg-primary-100 dark:bg-primary-900/40 px-1.5 py-0.5 rounded text-primary-800 dark:text-primary-200 text-xs font-mono border border-primary-200 dark:border-primary-800/50" 
                                          {...props}
                                        >
                                          {children}
                                        </code>
                                      );
                                    }

                                    return (
                                      <CodeBlock 
                                        language={match ? match[1] : 'text'} 
                                        value={String(children).replace(/\n$/, '')} 
                                        theme={theme}
                                        onShowToast={onShowToast}
                                        lang={language}
                                      />
                                    );
                                },
                                table({children}) {
                                    return <div className="overflow-x-auto my-4 rounded-lg border border-gray-200 dark:border-gray-700 shadow-sm bg-white/50 dark:bg-black/20"><table className="w-full text-left text-sm border-collapse">{children}</table></div>;
                                },
                                thead({children}) {
                                    return <thead className="bg-gray-50 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-300">{children}</thead>;
                                },
                                th({children}) {
                                    return <th className="px-4 py-3 font-semibold text-xs uppercase tracking-wider text-left">{children}</th>;
                                },
                                tr({children}) {
                                    return <tr className="border-b border-gray-100 dark:border-gray-800 last:border-0 hover:bg-gray-50/50 dark:hover:bg-gray-800/50 transition-colors">{children}</tr>;
                                },
                                td({children}) {
                                    return <td className="px-4 py-3 text-gray-600 dark:text-gray-300 align-top">{children}</td>;
                                },
                                a({href, children}) {
                                    return (
                                        <a 
                                            href={href} 
                                            target="_blank" 
                                            rel="noopener noreferrer" 
                                            className="text-primary-600 dark:text-primary-400 hover:underline hover:text-primary-700 dark:hover:text-primary-300 inline-flex items-center gap-0.5 font-medium transition-colors"
                                        >
                                            {children}
                                            <ExternalLink className="w-3 h-3 opacity-70" />
                                        </a>
                                    );
                                },
                                blockquote({children}) {
                                    return <blockquote className="border-l-4 border-primary-300 dark:border-primary-700 pl-4 py-2 my-4 text-gray-600 dark:text-gray-400 italic bg-gray-50/50 dark:bg-gray-800/30 rounded-r">{children}</blockquote>;
                                },
                                ul({children}) {
                                    return <ul className="list-disc pl-6 my-2 space-y-1 text-gray-700 dark:text-gray-300 marker:text-gray-400">{children}</ul>;
                                },
                                ol({children}) {
                                    return <ol className="list-decimal pl-6 my-2 space-y-1 text-gray-700 dark:text-gray-300 marker:text-gray-400">{children}</ol>;
                                },
                                li({children}) {
                                    return <li className="pl-1 leading-relaxed">{children}</li>;
                                },
                                h1({children}) {
                                    return <h1 className="text-2xl font-bold mt-6 mb-4 pb-2 border-b border-gray-200 dark:border-gray-700 text-gray-900 dark:text-white flex items-center gap-2">{children}</h1>;
                                },
                                h2({children}) {
                                    return <h2 className="text-xl font-bold mt-5 mb-3 text-gray-900 dark:text-white border-b border-gray-100 dark:border-gray-800 pb-1">{children}</h2>;
                                },
                                h3({children}) {
                                    return <h3 className="text-lg font-bold mt-4 mb-2 text-gray-900 dark:text-white">{children}</h3>;
                                },
                                h4({children}) {
                                    return <h4 className="text-base font-bold mt-3 mb-2 text-gray-900 dark:text-white">{children}</h4>;
                                },
                                hr({}) {
                                    return <hr className="my-6 border-gray-200 dark:border-gray-700" />;
                                },
                                img({src, alt}) {
                                    return <img src={src} alt={alt} className="max-w-full h-auto rounded-lg my-4 shadow-sm border border-gray-200 dark:border-gray-700 block mx-auto hover:opacity-95 transition-opacity cursor-pointer" loading="lazy" onClick={() => { if (typeof src === 'string') window.open(src, '_blank'); }} />;
                                },
                                del({children}) {
                                    return <del className="text-gray-400 dark:text-gray-500 line-through decoration-gray-400 dark:decoration-gray-500">{children}</del>;
                                },
                                input({checked, readOnly}) {
                                    return <input type="checkbox" checked={checked} readOnly={readOnly} className="mr-2 accent-primary-600 rounded w-4 h-4 align-text-bottom cursor-default" />;
                                }
                            }}
                        >
                            {/* Use clean content for markdown rendering */}
                            {content}
                        </ReactMarkdown>
                    </div>
                    )}
                </>
                )}
            </div>

            {/* Meta Info & Actions */}
            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="API Key Index">#{msg.keyIndex}</span>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title="Model Used">{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="Response Time">
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleTranslateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.translate', language)}
                    aria-label={t('action.translate', language)}
                    >
                    <Languages className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

"use client";

import React, { useRef, useEffect, useState, useLayoutEffect, useCallback } from 'react';
import { Message, Language, TextWrappingMode, Theme, Role, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { ChatMessage } from './ChatMessage';
import './ChatInterface.css';

interface ChatInterfaceProps {
  messages: Message[];
  isLoading: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  onTranslate: (id: string) => void; // New prop for translation
  language: Language;
  fontSize: number;
  textWrapping: TextWrappingMode;
  bubbleTransparency: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  theme: Theme;
  kirbyThemeColor: boolean;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  avatarVisibility: AvatarVisibility;
}

const LoadingTimer = () => {
  const [tenths, setTenths] = useState(0);

  useEffect(() => {
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      setTenths(Math.floor(elapsed / 100));
    }, 100);
    return () => clearInterval(interval);
  }, []);

  return (
    <span className="text-xs font-mono text-primary-600 dark:text-primary-400 ml-2 select-none min-w-[3ch]">
      {(tenths / 10).toFixed(1)}s
    </span>
  );
};

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    messages, 
    isLoading, 
    onEditMessage, 
    onDeleteMessage, 
    onRegenerate, 
    onTranslate,
    language, 
    fontSize, 
    textWrapping, 
    bubbleTransparency,
    showModelName,
    showResponseTimer = false,
    theme,
    kirbyThemeColor,
    onShowToast,
    smoothAnimation = true,
    avatarVisibility
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Track if the user has manually scrolled up to pause auto-scrolling
  const isUserScrolledUp = useRef(false);
  const scrollRafId = useRef<number | null>(null);
  const lastIsLoading = useRef(isLoading);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // --- Scroll Logic ---

  // 1. Check if user is near bottom to enable/disable sticky mode
  const handleScroll = () => {
    if (!scrollContainerRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;

    // Threshold to consider "at bottom". 
    // Small threshold (20px) ensures that if user scrolls up slightly, we respect it immediately (stop auto-scroll).
    const isAtBottom = scrollHeight - scrollTop - clientHeight < 20;

    // We strictly track this state to allow reading history while generating
    isUserScrolledUp.current = !isAtBottom;
  };

  // 2. Callback passed to ChatMessage to trigger scroll on text expansion
  // This ensures smooth scrolling even if the network request finished but animation is still playing
  const scrollToBottom = useCallback(() => {
     if (scrollContainerRef.current && !isUserScrolledUp.current) {
         // Force scroll to absolute bottom
         scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
     }
  }, []);

  // 3. Reset scroll lock when new messages are added (User sent one, or History loaded)
  useLayoutEffect(() => {
      isUserScrolledUp.current = false;
  }, [messages.length]);

  // 4. Initial Snap to Top on New Generation
  useLayoutEffect(() => {
    // Detect edge: isLoading goes false -> true (Start of generation)
    if (!lastIsLoading.current && isLoading) {
        // Reset user scroll lock
        isUserScrolledUp.current = false;

        // Find the AI message and snap it to top
        requestAnimationFrame(() => {
            if (scrollContainerRef.current) {
                const container = scrollContainerRef.current;
                const messageElements = container.querySelectorAll('[data-role="model"]');
                const lastModelMessage = messageElements[messageElements.length - 1];

                if (lastModelMessage) {
                    lastModelMessage.scrollIntoView({ block: 'start', behavior: 'smooth' });
                } else {
                    container.scrollTop = container.scrollHeight;
                }
            }
        });
    }
    lastIsLoading.current = isLoading;
  }, [isLoading]);


  // 5. The Sticky Loop (Bottom Tracking during loading)
  // This runs continuously while isLoading is true for network phase
  useEffect(() => {
    if (!isLoading) {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
      return;
    }

    const loop = () => {
      const container = scrollContainerRef.current;
      if (container && !isUserScrolledUp.current) {
        const { scrollHeight, scrollTop, clientHeight } = container;
        const distanceFromBottom = scrollHeight - (scrollTop + clientHeight);

        // Sticky logic: If content pushes down, follow it, but allow the "Snap to Top" gap
        // We only force scroll if the bottom is obscured by more than threshold
        if (distanceFromBottom > 20) {
            container.scrollTop = scrollHeight - clientHeight;
        }
      }
      scrollRafId.current = requestAnimationFrame(loop);
    };

    loop();

    return () => {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
    };
  }, [isLoading]);

  // 6. Fallback: Handle non-streaming loads
  useLayoutEffect(() => {
    if (!isLoading && scrollContainerRef.current && !isUserScrolledUp.current) {
       scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [messages.length, isLoading]);

  useEffect(() => {
    return () => {
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    };
  }, [messages]);

  const startEditing = (msg: Message) => { 
    setEditingId(msg.id); 
    setConfirmDeleteId(null);
  };

  // Calculate styles for loading bubble to match ChatMessage model bubbles
  const borderAlpha = 0.5 + (bubbleTransparency / 100) * 0.5;
  const loadingBubbleStyle = {
      backgroundColor: `rgba(var(--color-theme-primary-rgb), ${(bubbleTransparency / 100) * 0.15})`,
      borderColor: isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`
  };

  const showLoadingAvatar = avatarVisibility === 'always' || avatarVisibility === 'model-only';

  if (messages.length === 0) {
    return (
      <div className="empty-state">
        <div className="kirby-logo-large animate-fade-in-up">
            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
        </div>
        <h1 className="welcome-title">{t('app.title', language)}</h1>
        <p className="welcome-desc">{t('msg.welcome_desc', language)}</p>
      </div>
    );
  }

  return (
    <div 
        ref={scrollContainerRef}
        onScroll={handleScroll}
        className="chat-interface-container"
    >
      <div className="messages-wrapper">
        {messages.map((msg, index) => (
            <div key={msg.id} data-role={msg.role}>
                <ChatMessage
                    msg={msg}
                    isEditing={editingId === msg.id}
                    isConfirmingDelete={confirmDeleteId === msg.id}
                    isLoading={isLoading}
                    bubbleTransparency={bubbleTransparency}
                    textWrapping={textWrapping}
                    fontSize={fontSize}
                    showModelName={showModelName}
                    showResponseTimer={showResponseTimer}
                    language={language}
                    theme={theme}
                    kirbyThemeColor={kirbyThemeColor}
                    onEditMessage={onEditMessage}
                    onDeleteMessage={onDeleteMessage}
                    onRegenerate={onRegenerate}
                    onTranslate={onTranslate}
                    setEditingId={setEditingId}
                    setConfirmDeleteId={setConfirmDeleteId}
                    startEditing={startEditing}
                    deleteTimerRef={deleteTimerRef}
                    onShowToast={onShowToast}
                    smoothAnimation={smoothAnimation}
                    isLast={index === messages.length - 1}
                    onScrollToBottom={scrollToBottom}
                    avatarVisibility={avatarVisibility}
                />
            </div>
        ))}

        {isLoading && (
            <div className={`loading-indicator ${containerClass} animate-fade-in-up`} data-role="loading">
            <div className="flex gap-3">
                {showLoadingAvatar && (
                    <div className="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center overflow-hidden">
                        <div className="w-full h-full scale-150">
                            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
                        </div>
                    </div>
                )}
                <div 
                    className="loading-bubble"
                    style={loadingBubbleStyle}
                >
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                    {showResponseTimer && <LoadingTimer />}
                </div>
            </div>
            </div>
        )}

        {/* Dynamic Bottom Buffer */}
        <div 
            className="w-full transition-all duration-300 ease-out flex-shrink-0" 
            style={{ height: isLoading ? '160px' : '0px' }} 
            aria-hidden="true" 
        />
      </div>
    </div>
  );
};

export default ChatInterface;

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

// Lazy load heavy or hidden-by-default components
const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

// --- Default Configuration 默认配置 ---
const DEFAULT_MODEL = GeminiModel.FLASH;
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-2.5-flash', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 },
    { name: 'gemini-2.5-flash-thinking-preview-01-21', inputTokenLimit: 32768, outputTokenLimit: 8192 }
];

const App: React.FC = () => {
  // --- State 状态管理 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string>('');
  const [messages, setMessages] = useState<Message[]>([]);

  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocked, setIsLocked] = useState(false);

  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]);
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS);

  // 默认设置为中文 (zh)
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', // Default to Chinese
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  // UI State
  const [toasts, setToasts] = useState<ToastMessage[]>([] );
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- Helpers for UI 辅助函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  // --- Initialization 初始化逻辑 ---
  useEffect(() => {
    // 1. Load Keys & Migration (加载密钥与迁移)
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');

    // Retrieve old global settings to migrate model/url to keys
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = oldSettingsStr ? JSON.parse(oldSettingsStr) : null;
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = JSON.parse(storedKeys);
    } else if (oldKeysV3) {
      // Migrate v3 keys to v4: Add model and baseUrl to each key
      const parsed = JSON.parse(oldKeysV3);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5,
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    // 2. Load Settings (加载设置)
    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    // 2.1 Load Known Models from separate cache
    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        try {
            loadedKnownModels = JSON.parse(storedKnownModels);
        } catch (e) {
            // console.error("Failed to parse known models from storage", e);
        }
    }

    if (storedSettings) {
      const parsedSettings = JSON.parse(storedSettings);

      // Migration: If knownModels existed in settings but not in separate cache, use it
      if (parsedSettings.knownModels && !storedKnownModels) {
          loadedKnownModels = parsedSettings.knownModels;
      }

      // Remove knownModels from settings object if present
      if ('knownModels' in parsedSettings) {
          delete parsedSettings.knownModels;
      }

      loadedSettings = { ...settings, ...parsedSettings };

      // Ensure defaults for new settings
      if (loadedSettings.security && loadedSettings.security.lockoutDurationSeconds === undefined) {
          loadedSettings.security.lockoutDurationSeconds = 86400; 
      }
      if (loadedSettings.generation && loadedSettings.generation.stream === undefined) {
          loadedSettings.generation.stream = false;
      }
      if (loadedSettings.showModelName === undefined) {
          loadedSettings.showModelName = true;
      }
      if (loadedSettings.kirbyThemeColor === undefined) {
          loadedSettings.kirbyThemeColor = false;
      }
       if (loadedSettings.showTokenUsage === undefined) {
          loadedSettings.showTokenUsage = false;
      }
      if (loadedSettings.showResponseTimer === undefined) {
          loadedSettings.showResponseTimer = false;
      }
      if (loadedSettings.smoothAnimation === undefined) {
          loadedSettings.smoothAnimation = true;
      }
      if (loadedSettings.avatarVisibility === undefined) {
          loadedSettings.avatarVisibility = 'always';
      }
      if (loadedSettings.historyContextLimit === undefined) {
          loadedSettings.historyContextLimit = 0;
      }
      if (loadedSettings.generation && loadedSettings.generation.thinkingBudget === undefined) {
          loadedSettings.generation.thinkingBudget = 0;
      }
      if (loadedSettings.generation && loadedSettings.generation.stripThoughts === undefined) {
          loadedSettings.generation.stripThoughts = false;
      }
      if (loadedSettings.enableKeyGrouping === undefined) {
          loadedSettings.enableKeyGrouping = false;
      }
      if (loadedSettings.keyGroups === undefined) {
          loadedSettings.keyGroups = [];
      }
      if (!loadedSettings.scripts) {
          loadedSettings.scripts = {
              inputFilterEnabled: false,
              inputFilterCode: '',
              outputFilterEnabled: false,
              outputFilterCode: ''
          };
      }
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    // Init Service - calculate effective keys (masking inactive groups)
    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) {
            return { ...k, isActive: false };
        }
        return k;
    });

    setLlmService(new LLMService(effectiveKeys, (id, errorCode) => {
        setApiKeys(prev => prev.map(k => k.id === id ? { ...k, isActive: false, lastErrorCode: errorCode } : k));
        addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
    }));

    // Security check
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) {
            setIsLocked(true);
        } else {
             const newSettings = { ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } };
             setSettings(newSettings);
        }
    }

    // 3. Load Sessions (加载会话历史)
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = JSON.parse(storedSessions) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId))
          ? storedActiveId 
          : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else {
        createNewSession();
      }
    } else {
      createNewSession();
    }
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  // --- Persistence & Key Updates (持久化与密钥更新) ---
  useEffect(() => {
    // Determine effective keys to pass to LLMService based on Group status
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) {
            return { ...k, isActive: false };
        }
        return k;
    });

    if (llmService) {
      llmService.updateKeys(effectiveKeys);
    } else {
       setLlmService(new LLMService(effectiveKeys, (id, errorCode) => {
           setApiKeys(prev => prev.map(k => k.id === id ? { ...k, isActive: false, lastErrorCode: errorCode } : k));
           addToast(`${t('error.key_auto_disabled', settings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
       }));
    }
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  // --- Core Logic (核心聊天逻辑) ---

  // 核心回复逻辑：接收上下文和新消息，调用 LLM 服务流式输出
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    // Optimistic UI update
    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const combinedSystemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');

      // CRITICAL FIX: Ensure history passed to API does NOT contain the new user message.
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      // Apply "Strip Thoughts" if enabled
      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      // Apply History Context Limit (Truncate history sent to model)
      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', // Global model ignored, uses key config
        contextToSend, 
        userMessage.text, // Explicit prompt text
        combinedSystemInstruction,
        settings.generation,
        (chunkText) => {
           // Apply Output Filter (Streaming)
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(
                   settings.scripts.outputFilterCode,
                   chunkText,
                   { role: 'model', history: [...historyBefore, userMessage] }
               );
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;

      // Apply Output Filter (Final)
      let processedFinalText = fullText;
      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(
              settings.scripts.outputFilterCode,
              fullText,
              { role: 'model', history: [...historyBefore, userMessage] }
          );
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
          // If concurrent call error, show toast instead of chat message
          if (error.message === "error.call_in_progress") {
             addToast(t('error.call_in_progress', settings.language), 'error');
             // Remove the placeholder bot message
             setMessages(prev => prev.filter(m => m.id !== tempBotId));
          } else {
             // Other errors show in chat
             const errorMessage: Message = {
                id: uuidv4(),
                role: Role.MODEL,
                text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
                timestamp: Date.now(),
                isError: true,
                executionTime: Date.now() - startTime
             };
             setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
          }
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleUnlock = () => {
      setIsLocked(false);
      const newSettings = { ...settings, security: { ...settings.security, lastLogin: Date.now() } };
      setSettings(newSettings);
      localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(newSettings));
  };

  // 处理消息发送
  const handleSendMessage = async () => {
    // Prevent race conditions with isProcessingRef
    if (isLoading || !llmService || isProcessingRef.current) {
        if (isLoading) addToast(t('error.call_in_progress', settings.language), 'error');
        return;
    }

    if (!input.trim()) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; // Lock

    // Apply Input Filter
    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(
            settings.scripts.inputFilterCode, 
            processedInput, 
            { role: 'user', history: messages }
        );
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      timestamp: Date.now()
    };

    // Update UI immediately (Optimistic)
    setMessages(prev => [...prev, newMessage]);
    setInput('');

    try {
        // Pass the CURRENT messages (history before new message) and the NEW message object
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; // Unlock
    }
  };

  // 翻译消息
  const handleTranslate = async (id: string) => {
    if (isLoading || !llmService) return;
    const targetMsg = messages.find(m => m.id === id);
    if (!targetMsg) return;

    // 构建翻译请求
    // Construct translation request
    const prompt = `请将以下内容翻译为简体中文，保持原有格式（Markdown, 代码块等）：\n\n${targetMsg.text}`;

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: prompt,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    await triggerBotResponse(messages, newMessage);
  };

  const handleGetTokenCount = async (currentInput: string): Promise<number> => {
      if (!llmService || apiKeys.length === 0) return 0;

      const activeKey = apiKeys.find(k => k.isActive);
      if (!activeKey) return 0;

      let contextToSend = messages;
      // Strip thoughts for token counting if enabled
      if (settings.generation.stripThoughts) {
        contextToSend = messages.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      if (settings.historyContextLimit > 0 && contextToSend.length > settings.historyContextLimit) {
          contextToSend = contextToSend.slice(-settings.historyContextLimit);
      }

      const combinedSystemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');

      return await llmService.countTokens(
          activeKey,
          contextToSend,
          currentInput,
          combinedSystemInstruction
      );
  };

  const handleEditMessage = (id: string, newText: string) => {
    setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg));
  };

  const handleDeleteMessage = (id: string) => {
    setMessages(prev => prev.filter(msg => msg.id !== id));
  };

  const handleRegenerate = async (id: string) => {
    if (isLoading || !llmService) {
         if (isLoading) addToast(t('error.call_in_progress', settings.language), 'error');
         return;
    }

    const index = messages.findIndex(m => m.id === id);
    if (index === -1) return;
    const targetMsg = messages[index];

    if (targetMsg.role === Role.USER) {
       // Regenerate from User Message
       const historyBefore = messages.slice(0, index);
       await triggerBotResponse(historyBefore, targetMsg);
    } else {
      // Regenerate Model Response
      let userMsgIndex = index - 1;
      while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) {
        userMsgIndex--;
      }
      if (userMsgIndex === -1) {
        handleDeleteMessage(id);
        return;
      }
      const historyBefore = messages.slice(0, userMsgIndex);
      const userMsg = messages[userMsgIndex];
      await triggerBotResponse(historyBefore, userMsg);
    }
  };

  const handleNewChat = () => {
    handleStopGeneration();
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
    setInput('');
    setIsMobileMenuOpen(false);
  };

  const handleClearChat = () => {
      if (messages.length === 0) return;
      showDialog({
          type: 'confirm',
          title: t('action.clear_chat', settings.language),
          message: t('msg.confirm_clear_chat', settings.language),
          onConfirm: () => {
              handleStopGeneration();
              setMessages([]);
              setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
          }
      });
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const handleDeleteSession = (e: React.MouseEvent, sessionId: string) => {
    e.stopPropagation();
    const newSessions = sessions.filter(s => s.id !== sessionId);
    setSessions(newSessions);
    if (activeSessionId === sessionId) {
       handleStopGeneration();
       if (newSessions.length > 0) {
         setActiveSessionId(newSessions[0].id);
         setMessages(newSessions[0].messages);
       } else {
         createNewSession();
       }
    }
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || "Session";
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();
      setMessages(loadedMessages);
      setInput('');
      if (title) {
          setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: title } : s));
      }
      addToast(t('success.chat_import', settings.language), 'success');
  };

  const handleSummarize = async () => {
    if (messages.length === 0 || !llmService) return;
    if (isLoading) {
        addToast(t('error.call_in_progress', settings.language), 'error');
        return;
    }

    setIsSummarizing(true); 
    try {
        const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
        const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
        const { text } = await llmService.streamChatResponse('', [], prompt, undefined, settings.generation, undefined, undefined, settings.language);
        const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
        if (newTitle) {
            setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
            addToast(t('action.ok', settings.language), 'success');
        }
    } catch (error: any) {
        if (error.message === "error.call_in_progress") {
            addToast(t('error.call_in_progress', settings.language), 'error');
        } else {
            addToast(t('msg.summarize_error', settings.language), 'error');
        }
    } finally {
        setIsSummarizing(false);
    }
  };

  const handleRenameSession = () => {
    const currentSession = sessions.find(s => s.id === activeSessionId);
    const currentTitle = currentSession?.title || t('app.title', settings.language);

    showDialog({
        type: 'input',
        title: t('msg.rename_chat', settings.language),
        inputValue: currentTitle,
        onConfirm: (newTitle) => {
            if (newTitle && newTitle.trim()) {
                setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
            }
        }
    });
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${settings.theme === 'dark' || settings.theme === 'twilight' || settings.theme === 'vscode-dark' ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock 
                config={settings.security} 
                onUnlock={handleUnlock} 
                lang={settings.language} 
                theme={settings.theme}
                kirbyThemeColor={settings.kirbyThemeColor}
            />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${settings.theme === 'dark' || settings.theme === 'twilight' || settings.theme === 'vscode-dark' ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions}
            activeSessionId={activeSessionId}
            activeKeysCount={activeKeysCount}
            language={settings.language}
            theme={settings.theme}
            kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={handleNewChat}
            onSelectSession={handleSelectSession}
            onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen}
                sessions={sessions}
                activeSessionId={activeSessionId}
                language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)}
                onNewChat={handleNewChat}
                onSelectSession={handleSelectSession}
                onDeleteSession={handleDeleteSession}
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0">
          <Header 
             currentSessionTitle={currentSessionTitle}
             isSummarizing={isSummarizing}
             hasMessages={messages.length > 0}
             language={settings.language}
             onRename={handleRenameSession}
             onSummarize={handleSummarize}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
             onNewChat={handleNewChat}
             onClearChat={handleClearChat}
             onOpenSettings={() => setIsSettingsOpen(true)}
             onSaveChat={handleSaveChat}
             onLoadSession={handleLoadSession}
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} 
              isLoading={isLoading} 
              onEditMessage={handleEditMessage} 
              onDeleteMessage={handleDeleteMessage} 
              onRegenerate={handleRegenerate} 
              onTranslate={handleTranslate}
              language={settings.language} 
              fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping}
              bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName}
              showResponseTimer={settings.showResponseTimer}
              theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor}
              onShowToast={addToast}
              smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="flex-shrink-0 z-20 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-black dark:via-black/90 dark:to-transparent pt-4">
             <ChatInput 
                input={input}
                setInput={setInput}
                onSend={handleSendMessage}
                onStop={handleStopGeneration}
                isLoading={isLoading}
                isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize}
                language={settings.language}
                activeKeysCount={activeKeysCount}
                showTokenUsage={settings.showTokenUsage}
                history={messages}
                historyLimit={settings.historyContextLimit}
                onGetTokenCount={handleGetTokenCount}
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-1 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} 
                onClose={() => setIsSettingsOpen(false)} 
                apiKeys={apiKeys} 
                onUpdateKeys={setApiKeys} 
                settings={settings} 
                onUpdateSettings={setSettings} 
                llmService={llmService}
                onShowToast={addToast}
                onShowDialog={showDialog}
                knownModels={knownModels}
                onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;

import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * Service class for handling Multi-Provider LLM interactions.
 * Manages API key rotation, load balancing, and delegates to specific provider services (Google Gemini, OpenAI, or Ollama).
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyIndex: number = 0;
  private keyUsageCount: number = 0;
  private _isCallInProgress: boolean = false; // Lock to prevent concurrent calls

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;
  private onKeyError?: (id: string, errorCode?: string) => void;

  constructor(initialKeys: KeyConfig[], onKeyError?: (id: string, errorCode?: string) => void) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();
    this.onKeyError = onKeyError;
  }

  /**
   * Updates the pool of API keys available for rotation.
   * Resets usage counters if the key list changes significantly.
   */
  public updateKeys(newKeys: KeyConfig[]) {
    this.keys = newKeys;
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  /**
   * Lists available models for a specific key configuration.
   * Supports Google GenAI, OpenAI, and Ollama endpoints.
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    if (this._isCallInProgress) {
        throw new Error("error.call_in_progress"); // UI will translate this key
    }
    this._isCallInProgress = true;
    try {
        if (keyConfig.provider === 'openai') {
            if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
            return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
        } else if (keyConfig.provider === 'ollama') {
            // Allow empty baseUrl (defaults to /ollama-proxy)
            return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
        } else {
            // Google Implementation
            return await this.googleService.listModels(keyConfig.key);
        }
    } finally {
        this._isCallInProgress = false;
    }
  }

  /**
   * Tests connection for a specific key configuration to ensure validity.
   * Performs a minimal chat generation request or model list check.
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
      if (this._isCallInProgress) {
          throw new Error("error.call_in_progress");
      }
      this._isCallInProgress = true;
      try {
          const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');

          try {
              if (keyConfig.provider === 'openai') {
                  if (!keyConfig.baseUrl) return false;
                  return await this.openAIService.testChat(
                      keyConfig.key, 
                      keyConfig.baseUrl, 
                      modelToUse
                  );
              } else if (keyConfig.provider === 'ollama') {
                  // Allow empty baseUrl (defaults to /ollama-proxy)
                  return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
              } else {
                  return await this.googleService.testConnection(keyConfig.key, modelToUse);
              }
          } catch (e) {
              return false;
          }
      } finally {
          this._isCallInProgress = false;
      }
  }

  /**
   * Retrieves the next available active API key using a Round-Robin strategy.
   * Handles usage limits per key (Poll Count) and skips rate-limited keys.
   * 
   * --- 密钥轮询逻辑 (Key Rotation) ---
   * 1. 过滤活跃密钥
   * 2. 检查轮询次数限制 (Poll Count)
   * 3. 检查速率限制状态 (Rate Limit check)
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    // Simple round-robin strategy across ALL active keys
    const currentKey = activeKeys[this.keyIndex % activeKeys.length];

    // Check usage limits (Poll Count)
    if (this.keyUsageCount >= (currentKey.usageLimit || 1)) {
        this.keyIndex = (this.keyIndex + 1) % activeKeys.length;
        this.keyUsageCount = 0;
    }

    const selectedKey = activeKeys[this.keyIndex % activeKeys.length];

    // Check rate limits (basic check: skip if limited < 60s ago)
    if (selectedKey.isRateLimited && Date.now() - selectedKey.lastUsed < 60000) {
        // Find next non-limited key
        for (let i = 1; i < activeKeys.length; i++) {
            const nextIdx = (this.keyIndex + i) % activeKeys.length;
            const k = activeKeys[nextIdx];
            if (!k.isRateLimited || Date.now() - k.lastUsed > 60000) {
                this.keyIndex = nextIdx;
                this.keyUsageCount = 0;
                return k;
            }
        }
    }

    this.keyUsageCount++;
    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  /**
   * Streams chat response using the next available key and its specific configuration.
   * Handles retries on failure and switches keys automatically.
   * 
   * --- 流式响应处理 (Stream Handling) ---
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string }> {

    if (this._isCallInProgress) {
        throw new Error("error.call_in_progress");
    }
    this._isCallInProgress = true;

    try {
        const maxRetries = this.keys.filter(k => k.isActive).length * 2 || 2;
        let attempts = 0;
        const validHistory = history.filter(msg => msg.text && msg.text.trim().length > 0 && !msg.isError);

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                throw e;
            }

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-2.5-flash';

            try {
                let text = "";
                if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    text = await this.openAIService.streamChat(
                        keyConfig.key,
                        keyConfig.baseUrl,
                        modelToUse,
                        validHistory,
                        newMessage,
                        systemInstruction,
                        generationConfig,
                        onChunk,
                        abortSignal
                    );
                } else if (keyConfig.provider === 'ollama') {
                    // Allow empty baseUrl
                    text = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '',
                        modelToUse,
                        validHistory,
                        newMessage,
                        systemInstruction,
                        generationConfig,
                        keyConfig.key, // Optional API key
                        onChunk,
                        abortSignal
                    );
                } else {
                    // Google Gemini API Call delegated to GoogleService
                    text = await this.googleService.streamChat(
                        keyConfig.key,
                        modelToUse,
                        validHistory,
                        newMessage,
                        systemInstruction,
                        generationConfig,
                        onChunk,
                        abortSignal
                    );
                }

                return { 
                    text, 
                    usedKeyIndex: this.getKeyDisplayIndex(keyConfig.id), 
                    provider: keyConfig.provider,
                    usedModel: modelToUse
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                // Extract Error Code
                let errorCode = 'Error';
                if (error.status) { // e.g., from Gemini API client, or raw response status
                    errorCode = error.status.toString();
                } else if (error.statusCode) { // e.g., from some libraries
                    errorCode = error.statusCode.toString();
                } else {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) errorCode = match[0];
                     else if (error.message?.includes("429")) errorCode = "429";
                     else if (error.message?.includes(t('error.fetch_failed', 'en'))) errorCode = "Network"; // Specific code for network errors
                }

                // Auto-deactivate key on error if callback provided
                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode);
                }

                // Mark inactive locally to avoid reusing in this loop
                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    localKey.isActive = false;
                    localKey.lastErrorCode = errorCode;
                }

                attempts++;
                continue;
            }
        }
        throw new Error(t('error.all_keys_failed', lang));
    } finally {
        this._isCallInProgress = false;
    }
  }

  /**
   * Counts tokens for a given context.
   * Returns -1 if provider does not support counting (like generic OpenAI or Ollama) or error occurs.
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      if (this._isCallInProgress) {
          throw new Error("error.call_in_progress");
      }
      this._isCallInProgress = true;
      try {
          if (keyConfig.provider !== 'google') return -1;

          return await this.googleService.countTokens(
              keyConfig.key,
              keyConfig.model || 'gemini-2.5-flash',
              history,
              newMessage
          );
      } finally {
          this._isCallInProgress = false;
      }
  }
}

"use client";

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus, vs } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { User, AlertCircle, Check, Copy, X, Save, Edit2, RefreshCw, Trash2, Clock, Brain, ChevronDown, ChevronRight, ExternalLink, Languages } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  onTranslate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
}

const CodeBlock = ({ 
  value, 
  language, 
  lang, 
  theme,
  onShowToast 
}: { 
  value: string, 
  language: string, 
  lang: Language, 
  theme: Theme,
  onShowToast: (msg: string, type: 'success' | 'error' | 'info') => void 
}) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    onShowToast(t('action.copied_code', lang), 'success');
    setTimeout(() => setCopied(false), 2000);
  };

  // Determine syntax highlighter style based on app theme
  const isDarkTheme = ['dark', 'twilight', 'panda', 'vscode-dark'].includes(theme);
  const style = isDarkTheme ? vscDarkPlus : vs;

  return (
    <div className="relative my-4 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-[#1e1e1e] group shadow-sm">
      <div className="flex items-center justify-between px-3 py-2 bg-gray-100 dark:bg-[#252526] border-b border-gray-200 dark:border-gray-700">
        <span className="font-mono text-xs text-gray-500 dark:text-gray-400 font-medium">{language || 'text'}</span>
        <button 
          onClick={handleCopy} 
          className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-primary-600 dark:text-gray-400 dark:hover:text-primary-400 transition-colors bg-gray-200/50 dark:bg-gray-700/50 px-2 py-1 rounded"
          aria-label={copied ? t('action.copied_code', lang) : t('action.copy_code', lang)}
        >
          {copied ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
          <span>{copied ? t('action.copied', lang) : t('action.copy', lang)}</span>
        </button>
      </div>
      <div className="overflow-x-auto text-sm">
        <SyntaxHighlighter
          language={language || 'text'}
          style={style}
          customStyle={{
            margin: 0,
            padding: '1rem',
            background: 'transparent',
            fontSize: 'inherit',
          }}
          codeTagProps={{
            style: { fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace' }
          }}
        >
          {value}
        </SyntaxHighlighter>
      </div>
    </div>
  );
};

const AutoResizeTextarea = ({ 
  value, 
  onChange, 
  onKeyDown, 
  fontSize, 
  autoFocus,
  lang 
}: { 
  value: string, 
  onChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void, 
  onKeyDown: (e: React.KeyboardEvent) => void, 
  fontSize: number,
  autoFocus?: boolean,
  lang: Language
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useLayoutEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [value]);

  return (
    <textarea 
      ref={textareaRef}
      value={value} 
      onChange={onChange} 
      onKeyDown={onKeyDown} 
      className="w-full bg-transparent text-inherit rounded-none p-0 outline-none border-none focus:ring-0 resize-none overflow-hidden leading-relaxed font-inherit min-w-[200px] whitespace-normal break-words" 
      rows={1}
      style={{ fontSize: `${fontSize}px` }} 
      autoFocus={autoFocus} 
      aria-label={t('input.edit_message_content', lang)}
    />
  );
};

interface ThoughtBlockProps {
  text: string;
  lang: Language;
}

// Thought Block Component
const ThoughtBlock: React.FC<ThoughtBlockProps> = ({ text, lang }) => {
  const [isOpen, setIsOpen] = useState(false); 

  return (
    <div className="my-3 border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50/50 dark:bg-gray-800/30 overflow-hidden">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center gap-2 px-3 py-2 text-xs font-medium text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
      >
        <Brain className="w-3.5 h-3.5 text-gray-400" />
        <span>{t('label.thought_process', lang)}</span>
        <div className="ml-auto">
            {isOpen ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
        </div>
      </button>
      {isOpen && (
         <div className="px-3 py-2 border-t border-gray-200 dark:border-gray-700 text-xs font-mono text-gray-600 dark:text-gray-400 whitespace-pre-wrap leading-relaxed">
             {text}
         </div>
      )}
    </div>
  );
};

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  onTranslate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility
}) => {
  const [editText, setEditText] = useState(msg.text);

  // Local buffer state for smooth streaming
  const [displayedText, setDisplayedText] = useState(msg.text);
  const targetTextRef = useRef(msg.text);
  const animationRef = useRef<number>(0);

  // VSCode Theme Logic
  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl'; // Wider container (1.33x)

  // Sync target text when prop changes
  useEffect(() => {
    targetTextRef.current = msg.text;

    // If animation is disabled, or not a model message, or editing, sync immediately
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing) {
        setDisplayedText(msg.text);
    }
  }, [msg.text, msg.role, isEditing, smoothAnimation]);

  // Sync edit text when starting to edit
  useEffect(() => {
    if (isEditing) setEditText(msg.text);
  }, [isEditing, msg.text]);

  // Smooth Text Animation Loop
  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;

        // If synchronized, stop updates
        if (current === target) return current;

        // If current is longer than target (e.g. deletion/rewrite), sync immediately
        if (current.length > target.length) return target;

        // Determine speed based on buffer size (catch up logic)
        const diff = target.length - current.length;

        let chunk = 2;
        if (diff > 50) chunk = 5;
        if (diff > 100) chunk = 15;
        if (diff > 500) chunk = 50; 

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);

        return nextText;
      });

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation]);

  // Scroll Synchronization
  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing]);

  // Parse Text for Thoughts
  const { thoughts, content } = useMemo(() => {
    if (msg.role !== Role.MODEL || isEditing) {
        return { thoughts: [], content: displayedText };
    }

    const thinkRegex = /<think>([\s\S]*?)(?:<\/think>|$)/g;
    const extractedThoughts: string[] = [];
    let match;

    while ((match = thinkRegex.exec(displayedText)) !== null) {
        extractedThoughts.push(match[1]);
    }

    const cleanContent = displayedText.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();

    return { thoughts: extractedThoughts, content: cleanContent };
  }, [displayedText, msg.role, isEditing]);


  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== msg.text) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const handleTranslateClick = () => {
    onTranslate(msg.id);
    setConfirmDeleteId(null);
  }

  const getWrappingClass = () => {
    switch (textWrapping) {
      case 'forced': return 'whitespace-pre-wrap break-all';
      case 'auto': return 'whitespace-normal break-words';
      case 'default': default: return 'whitespace-pre-wrap break-words';
    }
  };

  // Dynamic opacity
  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  // Animation class
  const animationClass = smoothAnimation ? 'animate-pop-in' : '';

  const wrapperWidthClass = isEditing 
      ? 'w-full max-w-full' 
      : 'max-w-[95%] md:max-w-[85%]'; // Standard constraint

  // VSCode Themes: No border color
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  // Avatar Visibility Logic
  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {/* Avatar */}
            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            {/* Message Content Wrapper */}
            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                <>
                    {msg.isError ? (
                    <div className="flex items-center gap-2"><AlertCircle className="w-4 h-4" /><span>{msg.text}</span></div>
                    ) : (
                    <div className={`prose prose-sm max-w-none leading-relaxed dark:prose-invert ${getWrappingClass()}`} style={{ fontSize: `${fontSize}px` }}>
                        {/* Render Thought Blocks if present */}
                        {thoughts.length > 0 && (
                            <div className="mb-3 flex flex-col gap-2">
                                {thoughts.map((thought, idx) => (
                                    <ThoughtBlock key={idx} text={thought} lang={language} />
                                ))}
                            </div>
                        )}

                        <ReactMarkdown 
                            remarkPlugins={[remarkGfm, remarkMath]} 
                            rehypePlugins={[rehypeKatex]} 
                            components={{ 
                                code({node, className, children, ...props}) { 
                                    const match = /language-(\w+)/.exec(className || ''); 
                                    const isInline = !match && !String(children).includes('\n'); 

                                    if (isInline) {
                                      return (
                                        <code 
                                          className="bg-primary-100 dark:bg-primary-900/40 px-1.5 py-0.5 rounded text-primary-800 dark:text-primary-200 text-xs font-mono border border-primary-200 dark:border-primary-800/50" 
                                          {...props}
                                        >
                                          {children}
                                        </code>
                                      );
                                    }

                                    return (
                                      <CodeBlock 
                                        language={match ? match[1] : 'text'} 
                                        value={String(children).replace(/\n$/, '')} 
                                        theme={theme}
                                        onShowToast={onShowToast}
                                        lang={language}
                                      />
                                    );
                                },
                                table({children}) {
                                    return <div className="overflow-x-auto my-4 rounded-lg border border-gray-200 dark:border-gray-700 shadow-sm bg-white/50 dark:bg-black/20"><table className="w-full text-left text-sm border-collapse">{children}</table></div>;
                                },
                                thead({children}) {
                                    return <thead className="bg-gray-50 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-300">{children}</thead>;
                                },
                                th({children}) {
                                    return <th className="px-4 py-3 font-semibold text-xs uppercase tracking-wider text-left">{children}</th>;
                                },
                                tr({children}) {
                                    return <tr className="border-b border-gray-100 dark:border-gray-800 last:border-0 hover:bg-gray-50/50 dark:hover:bg-gray-800/50 transition-colors">{children}</tr>;
                                },
                                td({children}) {
                                    return <td className="px-4 py-3 text-gray-600 dark:text-gray-300 align-top">{children}</td>;
                                },
                                a({href, children}) {
                                    return (
                                        <a 
                                            href={href} 
                                            target="_blank" 
                                            rel="noopener noreferrer" 
                                            className="text-primary-600 dark:text-primary-400 hover:underline hover:text-primary-700 dark:hover:text-primary-300 inline-flex items-center gap-0.5 font-medium transition-colors"
                                        >
                                            {children}
                                            <ExternalLink className="w-3 h-3 opacity-70" />
                                        </a>
                                    );
                                },
                                blockquote({children}) {
                                    return <blockquote className="border-l-4 border-primary-300 dark:border-primary-700 pl-4 py-2 my-4 text-gray-600 dark:text-gray-400 italic bg-gray-50/50 dark:bg-gray-800/30 rounded-r">{children}</blockquote>;
                                },
                                ul({children}) {
                                    return <ul className="list-disc pl-6 my-2 space-y-1 text-gray-700 dark:text-gray-300 marker:text-gray-400">{children}</ul>;
                                },
                                ol({children}) {
                                    return <ol className="list-decimal pl-6 my-2 space-y-1 text-gray-700 dark:text-gray-300 marker:text-gray-400">{children}</ol>;
                                },
                                li({children}) {
                                    return <li className="pl-1 leading-relaxed">{children}</li>;
                                },
                                h1({children}) {
                                    return <h1 className="text-2xl font-bold mt-6 mb-4 pb-2 border-b border-gray-200 dark:border-gray-700 text-gray-900 dark:text-white flex items-center gap-2">{children}</h1>;
                                },
                                h2({children}) {
                                    return <h2 className="text-xl font-bold mt-5 mb-3 text-gray-900 dark:text-white border-b border-gray-100 dark:border-gray-800 pb-1">{children}</h2>;
                                },
                                h3({children}) {
                                    return <h3 className="text-lg font-bold mt-4 mb-2 text-gray-900 dark:text-white">{children}</h3>;
                                },
                                h4({children}) {
                                    return <h4 className="text-base font-bold mt-3 mb-2 text-gray-900 dark:text-white">{children}</h4>;
                                },
                                hr({}) {
                                    return <hr className="my-6 border-gray-200 dark:border-gray-700" />;
                                },
                                img({src, alt}) {
                                    return <img src={src} alt={alt} className="max-w-full h-auto rounded-lg my-4 shadow-sm border border-gray-200 dark:border-gray-700 block mx-auto hover:opacity-95 transition-opacity cursor-pointer" loading="lazy" onClick={() => { if (typeof src === 'string') window.open(src, '_blank'); }} />;
                                },
                                del({children}) {
                                    return <del className="text-gray-400 dark:text-gray-500 line-through decoration-gray-400 dark:decoration-gray-500">{children}</del>;
                                },
                                input({checked, readOnly}) {
                                    return <input type="checkbox" checked={checked} readOnly={readOnly} className="mr-2 accent-primary-600 rounded w-4 h-4 align-text-bottom cursor-default" />;
                                }
                            }}
                        >
                            {/* Use clean content for markdown rendering */}
                            {content}
                        </ReactMarkdown>
                    </div>
                    )}
                </>
                )}
            </div>

            {/* Meta Info & Actions */}
            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="API Key Index">#{msg.keyIndex}</span>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title="Model Used">{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="Response Time">
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleTranslateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.translate', language)}
                    aria-label={t('action.translate', language)}
                    >
                    <Languages className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

"use client";

import React, { useRef, useEffect, useState, useLayoutEffect, useCallback } from 'react';
import { Message, Language, TextWrappingMode, Theme, Role, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { ChatMessage } from './ChatMessage';
import './ChatInterface.css';

interface ChatInterfaceProps {
  messages: Message[];
  isLoading: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  onTranslate: (id: string) => void; // New prop for translation
  language: Language;
  fontSize: number;
  textWrapping: TextWrappingMode;
  bubbleTransparency: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  theme: Theme;
  kirbyThemeColor: boolean;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  avatarVisibility: AvatarVisibility;
}

const LoadingTimer = () => {
  const [tenths, setTenths] = useState(0);

  useEffect(() => {
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      setTenths(Math.floor(elapsed / 100));
    }, 100);
    return () => clearInterval(interval);
  }, []);

  return (
    <span className="text-xs font-mono text-primary-600 dark:text-primary-400 ml-2 select-none min-w-[3ch]">
      {(tenths / 10).toFixed(1)}s
    </span>
  );
};

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    messages, 
    isLoading, 
    onEditMessage, 
    onDeleteMessage, 
    onRegenerate, 
    onTranslate,
    language, 
    fontSize, 
    textWrapping, 
    bubbleTransparency,
    showModelName,
    showResponseTimer = false,
    theme,
    kirbyThemeColor,
    onShowToast,
    smoothAnimation = true,
    avatarVisibility
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Track if the user has manually scrolled up to pause auto-scrolling
  const isUserScrolledUp = useRef(false);
  const scrollRafId = useRef<number | null>(null);
  const lastIsLoading = useRef(isLoading);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // --- Scroll Logic ---

  // 1. Check if user is near bottom to enable/disable sticky mode
  const handleScroll = () => {
    if (!scrollContainerRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;

    // Threshold to consider "at bottom". 
    // Small threshold (20px) ensures that if user scrolls up slightly, we respect it immediately (stop auto-scroll).
    const isAtBottom = scrollHeight - scrollTop - clientHeight < 20;

    // We strictly track this state to allow reading history while generating
    isUserScrolledUp.current = !isAtBottom;
  };

  // 2. Callback passed to ChatMessage to trigger scroll on text expansion
  // This ensures smooth scrolling even if the network request finished but animation is still playing
  const scrollToBottom = useCallback(() => {
     if (scrollContainerRef.current && !isUserScrolledUp.current) {
         // Force scroll to absolute bottom
         scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
     }
  }, []);

  // 3. Reset scroll lock when new messages are added (User sent one, or History loaded)
  useLayoutEffect(() => {
      isUserScrolledUp.current = false;
  }, [messages.length]);

  // 4. Initial Snap to Top on New Generation
  useLayoutEffect(() => {
    // Detect edge: isLoading goes false -> true (Start of generation)
    if (!lastIsLoading.current && isLoading) {
        // Reset user scroll lock
        isUserScrolledUp.current = false;

        // Find the AI message and snap it to top
        requestAnimationFrame(() => {
            if (scrollContainerRef.current) {
                const container = scrollContainerRef.current;
                const messageElements = container.querySelectorAll('[data-role="model"]');
                const lastModelMessage = messageElements[messageElements.length - 1];

                if (lastModelMessage) {
                    lastModelMessage.scrollIntoView({ block: 'start', behavior: 'smooth' });
                } else {
                    container.scrollTop = container.scrollHeight;
                }
            }
        });
    }
    lastIsLoading.current = isLoading;
  }, [isLoading]);


  // 5. The Sticky Loop (Bottom Tracking during loading)
  // This runs continuously while isLoading is true for network phase
  useEffect(() => {
    if (!isLoading) {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
      return;
    }

    const loop = () => {
      const container = scrollContainerRef.current;
      if (container && !isUserScrolledUp.current) {
        const { scrollHeight, scrollTop, clientHeight } = container;
        const distanceFromBottom = scrollHeight - (scrollTop + clientHeight);

        // Sticky logic: If content pushes down, follow it, but allow the "Snap to Top" gap
        // We only force scroll if the bottom is obscured by more than threshold
        if (distanceFromBottom > 20) {
            container.scrollTop = scrollHeight - clientHeight;
        }
      }
      scrollRafId.current = requestAnimationFrame(loop);
    };

    loop();

    return () => {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
    };
  }, [isLoading]);

  // 6. Fallback: Handle non-streaming loads
  useLayoutEffect(() => {
    if (!isLoading && scrollContainerRef.current && !isUserScrolledUp.current) {
       scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [messages.length, isLoading]);

  useEffect(() => {
    return () => {
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    };
  }, [messages]);

  const startEditing = (msg: Message) => { 
    setEditingId(msg.id); 
    setConfirmDeleteId(null);
  };

  // Calculate styles for loading bubble to match ChatMessage model bubbles
  const borderAlpha = 0.5 + (bubbleTransparency / 100) * 0.5;
  const loadingBubbleStyle = {
      backgroundColor: `rgba(var(--color-theme-primary-rgb), ${(bubbleTransparency / 100) * 0.15})`,
      borderColor: isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`
  };

  const showLoadingAvatar = avatarVisibility === 'always' || avatarVisibility === 'model-only';

  if (messages.length === 0) {
    return (
      <div className="empty-state">
        <div className="kirby-logo-large animate-fade-in-up">
            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
        </div>
        <h1 className="welcome-title">{t('app.title', language)}</h1>
        <p className="welcome-desc">{t('msg.welcome_desc', language)}</p>
      </div>
    );
  }

  return (
    <div 
        ref={scrollContainerRef}
        onScroll={handleScroll}
        className="chat-interface-container"
    >
      <div className="messages-wrapper">
        {messages.map((msg, index) => (
            <div key={msg.id} data-role={msg.role}>
                <ChatMessage
                    msg={msg}
                    isEditing={editingId === msg.id}
                    isConfirmingDelete={confirmDeleteId === msg.id}
                    isLoading={isLoading}
                    bubbleTransparency={bubbleTransparency}
                    textWrapping={textWrapping}
                    fontSize={fontSize}
                    showModelName={showModelName}
                    showResponseTimer={showResponseTimer}
                    language={language}
                    theme={theme}
                    kirbyThemeColor={kirbyThemeColor}
                    onEditMessage={onEditMessage}
                    onDeleteMessage={onDeleteMessage}
                    onRegenerate={onRegenerate}
                    onTranslate={onTranslate}
                    setEditingId={setEditingId}
                    setConfirmDeleteId={setConfirmDeleteId}
                    startEditing={startEditing}
                    deleteTimerRef={deleteTimerRef}
                    onShowToast={onShowToast}
                    smoothAnimation={smoothAnimation}
                    isLast={index === messages.length - 1}
                    onScrollToBottom={scrollToBottom}
                    avatarVisibility={avatarVisibility}
                />
            </div>
        ))}

        {isLoading && (
            <div className={`loading-indicator ${containerClass} animate-fade-in-up`} data-role="loading">
            <div className="flex gap-3">
                {showLoadingAvatar && (
                    <div className="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center overflow-hidden">
                        <div className="w-full h-full scale-150">
                            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
                        </div>
                    </div>
                )}
                <div 
                    className="loading-bubble"
                    style={loadingBubbleStyle}
                >
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                    {showResponseTimer && <LoadingTimer />}
                </div>
            </div>
            </div>
        )}

        {/* Dynamic Bottom Buffer */}
        <div 
            className="w-full transition-all duration-300 ease-out flex-shrink-0" 
            style={{ height: isLoading ? '160px' : '0px' }} 
            aria-hidden="true" 
        />
      </div>
    </div>
  );
};

export default ChatInterface;

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

// Lazy load heavy or hidden-by-default components
const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

// --- Default Configuration 默认配置 ---
const DEFAULT_MODEL = GeminiModel.FLASH;
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-2.5-flash', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 },
    { name: 'gemini-2.5-flash-thinking-preview-01-21', inputTokenLimit: 32768, outputTokenLimit: 8192 }
];

const App: React.FC = () => {
  // --- State 状态管理 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string>('');
  const [messages, setMessages] = useState<Message[]>([]);

  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocked, setIsLocked] = useState(false);

  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]);
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS);

  // 默认设置为中文 (zh)
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', // Default to Chinese
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  // UI State
  const [toasts, setToasts] = useState<ToastMessage[]>([] );
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- Helpers for UI 辅助函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  // --- Initialization 初始化逻辑 ---
  useEffect(() => {
    // 1. Load Keys & Migration (加载密钥与迁移)
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');

    // Retrieve old global settings to migrate model/url to keys
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = oldSettingsStr ? JSON.parse(oldSettingsStr) : null;
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = JSON.parse(storedKeys);
    } else if (oldKeysV3) {
      // Migrate v3 keys to v4: Add model and baseUrl to each key
      const parsed = JSON.parse(oldKeysV3);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5,
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    // 2. Load Settings (加载设置)
    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    // 2.1 Load Known Models from separate cache
    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        try {
            loadedKnownModels = JSON.parse(storedKnownModels);
        } catch (e) {
            // console.error("Failed to parse known models from storage", e);
        }
    }

    if (storedSettings) {
      const parsedSettings = JSON.parse(storedSettings);

      // Migration: If knownModels existed in settings but not in separate cache, use it
      if (parsedSettings.knownModels && !storedKnownModels) {
          loadedKnownModels = parsedSettings.knownModels;
      }

      // Remove knownModels from settings object if present
      if ('knownModels' in parsedSettings) {
          delete parsedSettings.knownModels;
      }

      loadedSettings = { ...settings, ...parsedSettings };

      // Ensure defaults for new settings
      if (loadedSettings.security && loadedSettings.security.lockoutDurationSeconds === undefined) {
          loadedSettings.security.lockoutDurationSeconds = 86400; 
      }
      if (loadedSettings.generation && loadedSettings.generation.stream === undefined) {
          loadedSettings.generation.stream = false;
      }
      if (loadedSettings.showModelName === undefined) {
          loadedSettings.showModelName = true;
      }
      if (loadedSettings.kirbyThemeColor === undefined) {
          loadedSettings.kirbyThemeColor = false;
      }
       if (loadedSettings.showTokenUsage === undefined) {
          loadedSettings.showTokenUsage = false;
      }
      if (loadedSettings.showResponseTimer === undefined) {
          loadedSettings.showResponseTimer = false;
      }
      if (loadedSettings.smoothAnimation === undefined) {
          loadedSettings.smoothAnimation = true;
      }
      if (loadedSettings.avatarVisibility === undefined) {
          loadedSettings.avatarVisibility = 'always';
      }
      if (loadedSettings.historyContextLimit === undefined) {
          loadedSettings.historyContextLimit = 0;
      }
      if (loadedSettings.generation && loadedSettings.generation.thinkingBudget === undefined) {
          loadedSettings.generation.thinkingBudget = 0;
      }
      if (loadedSettings.generation && loadedSettings.generation.stripThoughts === undefined) {
          loadedSettings.generation.stripThoughts = false;
      }
      if (loadedSettings.enableKeyGrouping === undefined) {
          loadedSettings.enableKeyGrouping = false;
      }
      if (loadedSettings.keyGroups === undefined) {
          loadedSettings.keyGroups = [];
      }
      if (!loadedSettings.scripts) {
          loadedSettings.scripts = {
              inputFilterEnabled: false,
              inputFilterCode: '',
              outputFilterEnabled: false,
              outputFilterCode: ''
          };
      }
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    // Init Service - calculate effective keys (masking inactive groups)
    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) {
            return { ...k, isActive: false };
        }
        return k;
    });

    setLlmService(new LLMService(effectiveKeys, (id, errorCode) => {
        setApiKeys(prev => prev.map(k => k.id === id ? { ...k, isActive: false, lastErrorCode: errorCode } : k));
        addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
    }));

    // Security check
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) {
            setIsLocked(true);
        } else {
             const newSettings = { ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } };
             setSettings(newSettings);
        }
    }

    // 3. Load Sessions (加载会话历史)
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = JSON.parse(storedSessions) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId))
          ? storedActiveId 
          : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else {
        createNewSession();
      }
    } else {
      createNewSession();
    }
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  // --- Persistence & Key Updates (持久化与密钥更新) ---
  useEffect(() => {
    // Determine effective keys to pass to LLMService based on Group status
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) {
            return { ...k, isActive: false };
        }
        return k;
    });

    if (llmService) {
      llmService.updateKeys(effectiveKeys);
    } else {
       setLlmService(new LLMService(effectiveKeys, (id, errorCode) => {
           setApiKeys(prev => prev.map(k => k.id === id ? { ...k, isActive: false, lastErrorCode: errorCode } : k));
           addToast(`${t('error.key_auto_disabled', settings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
       }));
    }
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  // --- Core Logic (核心聊天逻辑) ---

  // 核心回复逻辑：接收上下文和新消息，调用 LLM 服务流式输出
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    // Optimistic UI update
    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const combinedSystemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');

      // CRITICAL FIX: Ensure history passed to API does NOT contain the new user message.
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      // Apply "Strip Thoughts" if enabled
      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      // Apply History Context Limit (Truncate history sent to model)
      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', // Global model ignored, uses key config
        contextToSend, 
        userMessage.text, // Explicit prompt text
        combinedSystemInstruction,
        settings.generation,
        (chunkText) => {
           // Apply Output Filter (Streaming)
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(
                   settings.scripts.outputFilterCode,
                   chunkText,
                   { role: 'model', history: [...historyBefore, userMessage] }
               );
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;

      // Apply Output Filter (Final)
      let processedFinalText = fullText;
      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(
              settings.scripts.outputFilterCode,
              fullText,
              { role: 'model', history: [...historyBefore, userMessage] }
          );
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
          // If concurrent call error, show toast instead of chat message
          if (error.message === "error.call_in_progress") {
             addToast(t('error.call_in_progress', settings.language), 'error');
             // Remove the placeholder bot message
             setMessages(prev => prev.filter(m => m.id !== tempBotId));
          } else {
             // Other errors show in chat
             const errorMessage: Message = {
                id: uuidv4(),
                role: Role.MODEL,
                text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
                timestamp: Date.now(),
                isError: true,
                executionTime: Date.now() - startTime
             };
             setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
          }
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleUnlock = () => {
      setIsLocked(false);
      const newSettings = { ...settings, security: { ...settings.security, lastLogin: Date.now() } };
      setSettings(newSettings);
      localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(newSettings));
  };

  // 处理消息发送
  const handleSendMessage = async () => {
    // Prevent race conditions with isProcessingRef
    if (isLoading || !llmService || isProcessingRef.current) {
        if (isLoading) addToast(t('error.call_in_progress', settings.language), 'error');
        return;
    }

    if (!input.trim()) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; // Lock

    // Apply Input Filter
    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(
            settings.scripts.inputFilterCode, 
            processedInput, 
            { role: 'user', history: messages }
        );
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      timestamp: Date.now()
    };

    // Update UI immediately (Optimistic)
    setMessages(prev => [...prev, newMessage]);
    setInput('');

    try {
        // Pass the CURRENT messages (history before new message) and the NEW message object
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; // Unlock
    }
  };

  // 翻译消息
  const handleTranslate = async (id: string) => {
    if (isLoading || !llmService) return;
    const targetMsg = messages.find(m => m.id === id);
    if (!targetMsg) return;

    // 构建翻译请求
    // Construct translation request
    const prompt = `请将以下内容翻译为简体中文，保持原有格式（Markdown, 代码块等）：\n\n${targetMsg.text}`;

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: prompt,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    await triggerBotResponse(messages, newMessage);
  };

  const handleGetTokenCount = async (currentInput: string): Promise<number> => {
      if (!llmService || apiKeys.length === 0) return 0;

      const activeKey = apiKeys.find(k => k.isActive);
      if (!activeKey) return 0;

      let contextToSend = messages;
      // Strip thoughts for token counting if enabled
      if (settings.generation.stripThoughts) {
        contextToSend = messages.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      if (settings.historyContextLimit > 0 && contextToSend.length > settings.historyContextLimit) {
          contextToSend = contextToSend.slice(-settings.historyContextLimit);
      }

      const combinedSystemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');

      return await llmService.countTokens(
          activeKey,
          contextToSend,
          currentInput,
          combinedSystemInstruction
      );
  };

  const handleEditMessage = (id: string, newText: string) => {
    setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg));
  };

  const handleDeleteMessage = (id: string) => {
    setMessages(prev => prev.filter(msg => msg.id !== id));
  };

  const handleRegenerate = async (id: string) => {
    if (isLoading || !llmService) {
         if (isLoading) addToast(t('error.call_in_progress', settings.language), 'error');
         return;
    }

    const index = messages.findIndex(m => m.id === id);
    if (index === -1) return;
    const targetMsg = messages[index];

    if (targetMsg.role === Role.USER) {
       // Regenerate from User Message
       const historyBefore = messages.slice(0, index);
       await triggerBotResponse(historyBefore, targetMsg);
    } else {
      // Regenerate Model Response
      let userMsgIndex = index - 1;
      while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) {
        userMsgIndex--;
      }
      if (userMsgIndex === -1) {
        handleDeleteMessage(id);
        return;
      }
      const historyBefore = messages.slice(0, userMsgIndex);
      const userMsg = messages[userMsgIndex];
      await triggerBotResponse(historyBefore, userMsg);
    }
  };

  const handleNewChat = () => {
    handleStopGeneration();
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
    setInput('');
    setIsMobileMenuOpen(false);
  };

  const handleClearChat = () => {
      if (messages.length === 0) return;
      showDialog({
          type: 'confirm',
          title: t('action.clear_chat', settings.language),
          message: t('msg.confirm_clear_chat', settings.language),
          onConfirm: () => {
              handleStopGeneration();
              setMessages([]);
              setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
          }
      });
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const handleDeleteSession = (e: React.MouseEvent, sessionId: string) => {
    e.stopPropagation();
    const newSessions = sessions.filter(s => s.id !== sessionId);
    setSessions(newSessions);
    if (activeSessionId === sessionId) {
       handleStopGeneration();
       if (newSessions.length > 0) {
         setActiveSessionId(newSessions[0].id);
         setMessages(newSessions[0].messages);
       } else {
         createNewSession();
       }
    }
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || "Session";
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();
      setMessages(loadedMessages);
      setInput('');
      if (title) {
          setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: title } : s));
      }
      addToast(t('success.chat_import', settings.language), 'success');
  };

  const handleSummarize = async () => {
    if (messages.length === 0 || !llmService) return;
    if (isLoading) {
        addToast(t('error.call_in_progress', settings.language), 'error');
        return;
    }

    setIsSummarizing(true); 
    try {
        const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
        const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
        const { text } = await llmService.streamChatResponse('', [], prompt, undefined, settings.generation, undefined, undefined, settings.language);
        const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
        if (newTitle) {
            setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
            addToast(t('action.ok', settings.language), 'success');
        }
    } catch (error: any) {
        if (error.message === "error.call_in_progress") {
            addToast(t('error.call_in_progress', settings.language), 'error');
        } else {
            addToast(t('msg.summarize_error', settings.language), 'error');
        }
    } finally {
        setIsSummarizing(false);
    }
  };

  const handleRenameSession = () => {
    const currentSession = sessions.find(s => s.id === activeSessionId);
    const currentTitle = currentSession?.title || t('app.title', settings.language);

    showDialog({
        type: 'input',
        title: t('msg.rename_chat', settings.language),
        inputValue: currentTitle,
        onConfirm: (newTitle) => {
            if (newTitle && newTitle.trim()) {
                setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
            }
        }
    });
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${settings.theme === 'dark' || settings.theme === 'twilight' || settings.theme === 'vscode-dark' ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock 
                config={settings.security} 
                onUnlock={handleUnlock} 
                lang={settings.language} 
                theme={settings.theme}
                kirbyThemeColor={settings.kirbyThemeColor}
            />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${settings.theme === 'dark' || settings.theme === 'twilight' || settings.theme === 'vscode-dark' ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions}
            activeSessionId={activeSessionId}
            activeKeysCount={activeKeysCount}
            language={settings.language}
            theme={settings.theme}
            kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={handleNewChat}
            onSelectSession={handleSelectSession}
            onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen}
                sessions={sessions}
                activeSessionId={activeSessionId}
                language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)}
                onNewChat={handleNewChat}
                onSelectSession={handleSelectSession}
                onDeleteSession={handleDeleteSession}
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0">
          <Header 
             currentSessionTitle={currentSessionTitle}
             isSummarizing={isSummarizing}
             hasMessages={messages.length > 0}
             language={settings.language}
             onRename={handleRenameSession}
             onSummarize={handleSummarize}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
             onNewChat={handleNewChat}
             onClearChat={handleClearChat}
             onOpenSettings={() => setIsSettingsOpen(true)}
             onSaveChat={handleSaveChat}
             onLoadSession={handleLoadSession}
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} 
              isLoading={isLoading} 
              onEditMessage={handleEditMessage} 
              onDeleteMessage={handleDeleteMessage} 
              onRegenerate={handleRegenerate} 
              onTranslate={handleTranslate}
              language={settings.language} 
              fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping}
              bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName}
              showResponseTimer={settings.showResponseTimer}
              theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor}
              onShowToast={addToast}
              smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="flex-shrink-0 z-20 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-black dark:via-black/90 dark:to-transparent pt-4">
             <ChatInput 
                input={input}
                setInput={setInput}
                onSend={handleSendMessage}
                onStop={handleStopGeneration}
                isLoading={isLoading}
                isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize}
                language={settings.language}
                activeKeysCount={activeKeysCount}
                showTokenUsage={settings.showTokenUsage}
                history={messages}
                historyLimit={settings.historyContextLimit}
                onGetTokenCount={handleGetTokenCount}
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-1 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} 
                onClose={() => setIsSettingsOpen(false)} 
                apiKeys={apiKeys} 
                onUpdateKeys={setApiKeys} 
                settings={settings} 
                onUpdateSettings={setSettings} 
                llmService={llmService}
                onShowToast={addToast}
                onShowDialog={showDialog}
                knownModels={knownModels}
                onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;

import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * Service class for handling Multi-Provider LLM interactions.
 * Manages API key rotation, load balancing, and delegates to specific provider services (Google Gemini, OpenAI, or Ollama).
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyIndex: number = 0;
  private keyUsageCount: number = 0;
  private _isCallInProgress: boolean = false; // Lock to prevent concurrent calls

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;
  private onKeyError?: (id: string, errorCode?: string) => void;

  constructor(initialKeys: KeyConfig[], onKeyError?: (id: string, errorCode?: string) => void) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();
    this.onKeyError = onKeyError;
  }

  /**
   * Updates the pool of API keys available for rotation.
   * Resets usage counters if the key list changes significantly.
   */
  public updateKeys(newKeys: KeyConfig[]) {
    this.keys = newKeys;
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  /**
   * Lists available models for a specific key configuration.
   * Supports Google GenAI, OpenAI, and Ollama endpoints.
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    if (this._isCallInProgress) {
        throw new Error("error.call_in_progress"); // UI will translate this key
    }
    this._isCallInProgress = true;
    try {
        if (keyConfig.provider === 'openai') {
            if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
            return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
        } else if (keyConfig.provider === 'ollama') {
            // Allow empty baseUrl (defaults to /ollama-proxy)
            return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
        } else {
            // Google Implementation
            return await this.googleService.listModels(keyConfig.key);
        }
    } finally {
        this._isCallInProgress = false;
    }
  }

  /**
   * Tests connection for a specific key configuration to ensure validity.
   * Performs a minimal chat generation request or model list check.
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
      if (this._isCallInProgress) {
          throw new Error("error.call_in_progress");
      }
      this._isCallInProgress = true;
      try {
          const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');

          try {
              if (keyConfig.provider === 'openai') {
                  if (!keyConfig.baseUrl) return false;
                  return await this.openAIService.testChat(
                      keyConfig.key, 
                      keyConfig.baseUrl, 
                      modelToUse
                  );
              } else if (keyConfig.provider === 'ollama') {
                  // Allow empty baseUrl (defaults to /ollama-proxy)
                  return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
              } else {
                  return await this.googleService.testConnection(keyConfig.key, modelToUse);
              }
          } catch (e) {
              return false;
          }
      } finally {
          this._isCallInProgress = false;
      }
  }

  /**
   * Retrieves the next available active API key using a Round-Robin strategy.
   * Handles usage limits per key (Poll Count) and skips rate-limited keys.
   * 
   * --- 密钥轮询逻辑 (Key Rotation) ---
   * 1. 过滤活跃密钥
   * 2. 检查轮询次数限制 (Poll Count)
   * 3. 检查速率限制状态 (Rate Limit check)
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    // Simple round-robin strategy across ALL active keys
    const currentKey = activeKeys[this.keyIndex % activeKeys.length];

    // Check usage limits (Poll Count)
    if (this.keyUsageCount >= (currentKey.usageLimit || 1)) {
        this.keyIndex = (this.keyIndex + 1) % activeKeys.length;
        this.keyUsageCount = 0;
    }

    const selectedKey = activeKeys[this.keyIndex % activeKeys.length];

    // Check rate limits (basic check: skip if limited < 60s ago)
    if (selectedKey.isRateLimited && Date.now() - selectedKey.lastUsed < 60000) {
        // Find next non-limited key
        for (let i = 1; i < activeKeys.length; i++) {
            const nextIdx = (this.keyIndex + i) % activeKeys.length;
            const k = activeKeys[nextIdx];
            if (!k.isRateLimited || Date.now() - k.lastUsed > 60000) {
                this.keyIndex = nextIdx;
                this.keyUsageCount = 0;
                return k;
            }
        }
    }

    this.keyUsageCount++;
    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  /**
   * Streams chat response using the next available key and its specific configuration.
   * Handles retries on failure and switches keys automatically.
   * 
   * --- 流式响应处理 (Stream Handling) ---
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string }> {

    if (this._isCallInProgress) {
        throw new Error("error.call_in_progress");
    }
    this._isCallInProgress = true;

    try {
        const maxRetries = this.keys.filter(k => k.isActive).length * 2 || 2;
        let attempts = 0;
        const validHistory = history.filter(msg => msg.text && msg.text.trim().length > 0 && !msg.isError);

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                throw e;
            }

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-2.5-flash';

            try {
                let text = "";
                if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    text = await this.openAIService.streamChat(
                        keyConfig.key,
                        keyConfig.baseUrl,
                        modelToUse,
                        validHistory,
                        newMessage,
                        systemInstruction,
                        generationConfig,
                        onChunk,
                        abortSignal
                    );
                } else if (keyConfig.provider === 'ollama') {
                    // Allow empty baseUrl
                    text = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '',
                        modelToUse,
                        validHistory,
                        newMessage,
                        systemInstruction,
                        generationConfig,
                        keyConfig.key, // Optional API key
                        onChunk,
                        abortSignal
                    );
                } else {
                    // Google Gemini API Call delegated to GoogleService
                    text = await this.googleService.streamChat(
                        keyConfig.key,
                        modelToUse,
                        validHistory,
                        newMessage,
                        systemInstruction,
                        generationConfig,
                        onChunk,
                        abortSignal
                    );
                }

                return { 
                    text, 
                    usedKeyIndex: this.getKeyDisplayIndex(keyConfig.id), 
                    provider: keyConfig.provider,
                    usedModel: modelToUse
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                // Extract Error Code
                let errorCode = 'Error';
                if (error.status) { // e.g., from Gemini API client, or raw response status
                    errorCode = error.status.toString();
                } else if (error.statusCode) { // e.g., from some libraries
                    errorCode = error.statusCode.toString();
                } else {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) errorCode = match[0];
                     else if (error.message?.includes("429")) errorCode = "429";
                     else if (error.message?.includes(t('error.fetch_failed', 'en'))) errorCode = "Network"; // Specific code for network errors
                }

                // Auto-deactivate key on error if callback provided
                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode);
                }

                // Mark inactive locally to avoid reusing in this loop
                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    localKey.isActive = false;
                    localKey.lastErrorCode = errorCode;
                }

                attempts++;
                continue;
            }
        }
        throw new Error(t('error.all_keys_failed', lang));
    } finally {
        this._isCallInProgress = false;
    }
  }

  /**
   * Counts tokens for a given context.
   * Returns -1 if provider does not support counting (like generic OpenAI or Ollama) or error occurs.
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      if (this._isCallInProgress) {
          throw new Error("error.call_in_progress");
      }
      this._isCallInProgress = true;
      try {
          if (keyConfig.provider !== 'google') return -1;

          return await this.googleService.countTokens(
              keyConfig.key,
              keyConfig.model || 'gemini-2.5-flash',
              history,
              newMessage
          );
      } finally {
          this._isCallInProgress = false;
      }
  }
}

"use client";

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus, vs } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { User, AlertCircle, Check, Copy, X, Save, Edit2, RefreshCw, Trash2, Clock, Brain, ChevronDown, ChevronRight, ExternalLink, Languages } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  onTranslate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
}

const CodeBlock = ({ 
  value, 
  language, 
  lang, 
  theme,
  onShowToast 
}: { 
  value: string, 
  language: string, 
  lang: Language, 
  theme: Theme,
  onShowToast: (msg: string, type: 'success' | 'error' | 'info') => void 
}) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    onShowToast(t('action.copied_code', lang), 'success');
    setTimeout(() => setCopied(false), 2000);
  };

  // Determine syntax highlighter style based on app theme
  const isDarkTheme = ['dark', 'twilight', 'panda', 'vscode-dark'].includes(theme);
  const style = isDarkTheme ? vscDarkPlus : vs;

  return (
    <div className="relative my-4 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-[#1e1e1e] group shadow-sm">
      <div className="flex items-center justify-between px-3 py-2 bg-gray-100 dark:bg-[#252526] border-b border-gray-200 dark:border-gray-700">
        <span className="font-mono text-xs text-gray-500 dark:text-gray-400 font-medium">{language || 'text'}</span>
        <button 
          onClick={handleCopy} 
          className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-primary-600 dark:text-gray-400 dark:hover:text-primary-400 transition-colors bg-gray-200/50 dark:bg-gray-700/50 px-2 py-1 rounded"
          aria-label={copied ? t('action.copied_code', lang) : t('action.copy_code', lang)}
        >
          {copied ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
          <span>{copied ? t('action.copied', lang) : t('action.copy', lang)}</span>
        </button>
      </div>
      <div className="overflow-x-auto text-sm">
        <SyntaxHighlighter
          language={language || 'text'}
          style={style}
          customStyle={{
            margin: 0,
            padding: '1rem',
            background: 'transparent',
            fontSize: 'inherit',
          }}
          codeTagProps={{
            style: { fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace' }
          }}
        >
          {value}
        </SyntaxHighlighter>
      </div>
    </div>
  );
};

const AutoResizeTextarea = ({ 
  value, 
  onChange, 
  onKeyDown, 
  fontSize, 
  autoFocus,
  lang 
}: { 
  value: string, 
  onChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void, 
  onKeyDown: (e: React.KeyboardEvent) => void, 
  fontSize: number,
  autoFocus?: boolean,
  lang: Language
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useLayoutEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [value]);

  return (
    <textarea 
      ref={textareaRef}
      value={value} 
      onChange={onChange} 
      onKeyDown={onKeyDown} 
      className="w-full bg-transparent text-inherit rounded-none p-0 outline-none border-none focus:ring-0 resize-none overflow-hidden leading-relaxed font-inherit min-w-[200px] whitespace-normal break-words" 
      rows={1}
      style={{ fontSize: `${fontSize}px` }} 
      autoFocus={autoFocus} 
      aria-label={t('input.edit_message_content', lang)}
    />
  );
};

interface ThoughtBlockProps {
  text: string;
  lang: Language;
}

// Thought Block Component
const ThoughtBlock: React.FC<ThoughtBlockProps> = ({ text, lang }) => {
  const [isOpen, setIsOpen] = useState(false); 

  return (
    <div className="my-3 border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50/50 dark:bg-gray-800/30 overflow-hidden">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center gap-2 px-3 py-2 text-xs font-medium text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
      >
        <Brain className="w-3.5 h-3.5 text-gray-400" />
        <span>{t('label.thought_process', lang)}</span>
        <div className="ml-auto">
            {isOpen ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
        </div>
      </button>
      {isOpen && (
         <div className="px-3 py-2 border-t border-gray-200 dark:border-gray-700 text-xs font-mono text-gray-600 dark:text-gray-400 whitespace-pre-wrap leading-relaxed">
             {text}
         </div>
      )}
    </div>
  );
};

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  onTranslate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility
}) => {
  const [editText, setEditText] = useState(msg.text);

  // Local buffer state for smooth streaming
  const [displayedText, setDisplayedText] = useState(msg.text);
  const targetTextRef = useRef(msg.text);
  const animationRef = useRef<number>(0);

  // VSCode Theme Logic
  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl'; // Wider container (1.33x)

  // Sync target text when prop changes
  useEffect(() => {
    targetTextRef.current = msg.text;

    // If animation is disabled, or not a model message, or editing, sync immediately
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing) {
        setDisplayedText(msg.text);
    }
  }, [msg.text, msg.role, isEditing, smoothAnimation]);

  // Sync edit text when starting to edit
  useEffect(() => {
    if (isEditing) setEditText(msg.text);
  }, [isEditing, msg.text]);

  // Smooth Text Animation Loop
  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;

        // If synchronized, stop updates
        if (current === target) return current;

        // If current is longer than target (e.g. deletion/rewrite), sync immediately
        if (current.length > target.length) return target;

        // Determine speed based on buffer size (catch up logic)
        const diff = target.length - current.length;

        let chunk = 2;
        if (diff > 50) chunk = 5;
        if (diff > 100) chunk = 15;
        if (diff > 500) chunk = 50; 

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);

        return nextText;
      });

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation]);

  // Scroll Synchronization
  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing]);

  // Parse Text for Thoughts
  const { thoughts, content } = useMemo(() => {
    if (msg.role !== Role.MODEL || isEditing) {
        return { thoughts: [], content: displayedText };
    }

    const thinkRegex = /<think>([\s\S]*?)(?:<\/think>|$)/g;
    const extractedThoughts: string[] = [];
    let match;

    while ((match = thinkRegex.exec(displayedText)) !== null) {
        extractedThoughts.push(match[1]);
    }

    const cleanContent = displayedText.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();

    return { thoughts: extractedThoughts, content: cleanContent };
  }, [displayedText, msg.role, isEditing]);


  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== msg.text) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const handleTranslateClick = () => {
    onTranslate(msg.id);
    setConfirmDeleteId(null);
  }

  const getWrappingClass = () => {
    switch (textWrapping) {
      case 'forced': return 'whitespace-pre-wrap break-all';
      case 'auto': return 'whitespace-normal break-words';
      case 'default': default: return 'whitespace-pre-wrap break-words';
    }
  };

  // Dynamic opacity
  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  // Animation class
  const animationClass = smoothAnimation ? 'animate-pop-in' : '';

  const wrapperWidthClass = isEditing 
      ? 'w-full max-w-full' 
      : 'max-w-[95%] md:max-w-[85%]'; // Standard constraint

  // VSCode Themes: No border color
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  // Avatar Visibility Logic
  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {/* Avatar */}
            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            {/* Message Content Wrapper */}
            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                <>
                    {msg.isError ? (
                    <div className="flex items-center gap-2"><AlertCircle className="w-4 h-4" /><span>{msg.text}</span></div>
                    ) : (
                    <div className={`prose prose-sm max-w-none leading-relaxed dark:prose-invert ${getWrappingClass()}`} style={{ fontSize: `${fontSize}px` }}>
                        {/* Render Thought Blocks if present */}
                        {thoughts.length > 0 && (
                            <div className="mb-3 flex flex-col gap-2">
                                {thoughts.map((thought, idx) => (
                                    <ThoughtBlock key={idx} text={thought} lang={language} />
                                ))}
                            </div>
                        )}

                        <ReactMarkdown 
                            remarkPlugins={[remarkGfm, remarkMath]} 
                            rehypePlugins={[rehypeKatex]} 
                            components={{ 
                                code({node, className, children, ...props}) { 
                                    const match = /language-(\w+)/.exec(className || ''); 
                                    const isInline = !match && !String(children).includes('\n'); 

                                    if (isInline) {
                                      return (
                                        <code 
                                          className="bg-primary-100 dark:bg-primary-900/40 px-1.5 py-0.5 rounded text-primary-800 dark:text-primary-200 text-xs font-mono border border-primary-200 dark:border-primary-800/50" 
                                          {...props}
                                        >
                                          {children}
                                        </code>
                                      );
                                    }

                                    return (
                                      <CodeBlock 
                                        language={match ? match[1] : 'text'} 
                                        value={String(children).replace(/\n$/, '')} 
                                        theme={theme}
                                        onShowToast={onShowToast}
                                        lang={language}
                                      />
                                    );
                                },
                                table({children}) {
                                    return <div className="overflow-x-auto my-4 rounded-lg border border-gray-200 dark:border-gray-700 shadow-sm bg-white/50 dark:bg-black/20"><table className="w-full text-left text-sm border-collapse">{children}</table></div>;
                                },
                                thead({children}) {
                                    return <thead className="bg-gray-50 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-300">{children}</thead>;
                                },
                                th({children}) {
                                    return <th className="px-4 py-3 font-semibold text-xs uppercase tracking-wider text-left">{children}</th>;
                                },
                                tr({children}) {
                                    return <tr className="border-b border-gray-100 dark:border-gray-800 last:border-0 hover:bg-gray-50/50 dark:hover:bg-gray-800/50 transition-colors">{children}</tr>;
                                },
                                td({children}) {
                                    return <td className="px-4 py-3 text-gray-600 dark:text-gray-300 align-top">{children}</td>;
                                },
                                a({href, children}) {
                                    return (
                                        <a 
                                            href={href} 
                                            target="_blank" 
                                            rel="noopener noreferrer" 
                                            className="text-primary-600 dark:text-primary-400 hover:underline hover:text-primary-700 dark:hover:text-primary-300 inline-flex items-center gap-0.5 font-medium transition-colors"
                                        >
                                            {children}
                                            <ExternalLink className="w-3 h-3 opacity-70" />
                                        </a>
                                    );
                                },
                                blockquote({children}) {
                                    return <blockquote className="border-l-4 border-primary-300 dark:border-primary-700 pl-4 py-2 my-4 text-gray-600 dark:text-gray-400 italic bg-gray-50/50 dark:bg-gray-800/30 rounded-r">{children}</blockquote>;
                                },
                                ul({children}) {
                                    return <ul className="list-disc pl-6 my-2 space-y-1 text-gray-700 dark:text-gray-300 marker:text-gray-400">{children}</ul>;
                                },
                                ol({children}) {
                                    return <ol className="list-decimal pl-6 my-2 space-y-1 text-gray-700 dark:text-gray-300 marker:text-gray-400">{children}</ol>;
                                },
                                li({children}) {
                                    return <li className="pl-1 leading-relaxed">{children}</li>;
                                },
                                h1({children}) {
                                    return <h1 className="text-2xl font-bold mt-6 mb-4 pb-2 border-b border-gray-200 dark:border-gray-700 text-gray-900 dark:text-white flex items-center gap-2">{children}</h1>;
                                },
                                h2({children}) {
                                    return <h2 className="text-xl font-bold mt-5 mb-3 text-gray-900 dark:text-white border-b border-gray-100 dark:border-gray-800 pb-1">{children}</h2>;
                                },
                                h3({children}) {
                                    return <h3 className="text-lg font-bold mt-4 mb-2 text-gray-900 dark:text-white">{children}</h3>;
                                },
                                h4({children}) {
                                    return <h4 className="text-base font-bold mt-3 mb-2 text-gray-900 dark:text-white">{children}</h4>;
                                },
                                hr({}) {
                                    return <hr className="my-6 border-gray-200 dark:border-gray-700" />;
                                },
                                img({src, alt}) {
                                    return <img src={src} alt={alt} className="max-w-full h-auto rounded-lg my-4 shadow-sm border border-gray-200 dark:border-gray-700 block mx-auto hover:opacity-95 transition-opacity cursor-pointer" loading="lazy" onClick={() => { if (typeof src === 'string') window.open(src, '_blank'); }} />;
                                },
                                del({children}) {
                                    return <del className="text-gray-400 dark:text-gray-500 line-through decoration-gray-400 dark:decoration-gray-500">{children}</del>;
                                },
                                input({checked, readOnly}) {
                                    return <input type="checkbox" checked={checked} readOnly={readOnly} className="mr-2 accent-primary-600 rounded w-4 h-4 align-text-bottom cursor-default" />;
                                }
                            }}
                        >
                            {/* Use clean content for markdown rendering */}
                            {content}
                        </ReactMarkdown>
                    </div>
                    )}
                </>
                )}
            </div>

            {/* Meta Info & Actions */}
            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="API Key Index">#{msg.keyIndex}</span>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title="Model Used">{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="Response Time">
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleTranslateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.translate', language)}
                    aria-label={t('action.translate', language)}
                    >
                    <Languages className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

"use client";

import React, { useRef, useEffect, useState, useLayoutEffect, useCallback } from 'react';
import { Message, Language, TextWrappingMode, Theme, Role, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { ChatMessage } from './ChatMessage';
import './ChatInterface.css';

interface ChatInterfaceProps {
  messages: Message[];
  isLoading: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  onTranslate: (id: string) => void; // New prop for translation
  language: Language;
  fontSize: number;
  textWrapping: TextWrappingMode;
  bubbleTransparency: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  theme: Theme;
  kirbyThemeColor: boolean;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  avatarVisibility: AvatarVisibility;
}

const LoadingTimer = () => {
  const [tenths, setTenths] = useState(0);

  useEffect(() => {
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      setTenths(Math.floor(elapsed / 100));
    }, 100);
    return () => clearInterval(interval);
  }, []);

  return (
    <span className="text-xs font-mono text-primary-600 dark:text-primary-400 ml-2 select-none min-w-[3ch]">
      {(tenths / 10).toFixed(1)}s
    </span>
  );
};

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    messages, 
    isLoading, 
    onEditMessage, 
    onDeleteMessage, 
    onRegenerate, 
    onTranslate,
    language, 
    fontSize, 
    textWrapping, 
    bubbleTransparency,
    showModelName,
    showResponseTimer = false,
    theme,
    kirbyThemeColor,
    onShowToast,
    smoothAnimation = true,
    avatarVisibility
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Track if the user has manually scrolled up to pause auto-scrolling
  const isUserScrolledUp = useRef(false);
  const scrollRafId = useRef<number | null>(null);
  const lastIsLoading = useRef(isLoading);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // --- Scroll Logic ---

  // 1. Check if user is near bottom to enable/disable sticky mode
  const handleScroll = () => {
    if (!scrollContainerRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;

    // Threshold to consider "at bottom". 
    // Small threshold (20px) ensures that if user scrolls up slightly, we respect it immediately (stop auto-scroll).
    const isAtBottom = scrollHeight - scrollTop - clientHeight < 20;

    // We strictly track this state to allow reading history while generating
    isUserScrolledUp.current = !isAtBottom;
  };

  // 2. Callback passed to ChatMessage to trigger scroll on text expansion
  // This ensures smooth scrolling even if the network request finished but animation is still playing
  const scrollToBottom = useCallback(() => {
     if (scrollContainerRef.current && !isUserScrolledUp.current) {
         // Force scroll to absolute bottom
         scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
     }
  }, []);

  // 3. Reset scroll lock when new messages are added (User sent one, or History loaded)
  useLayoutEffect(() => {
      isUserScrolledUp.current = false;
  }, [messages.length]);

  // 4. Initial Snap to Top on New Generation
  useLayoutEffect(() => {
    // Detect edge: isLoading goes false -> true (Start of generation)
    if (!lastIsLoading.current && isLoading) {
        // Reset user scroll lock
        isUserScrolledUp.current = false;

        // Find the AI message and snap it to top
        requestAnimationFrame(() => {
            if (scrollContainerRef.current) {
                const container = scrollContainerRef.current;
                const messageElements = container.querySelectorAll('[data-role="model"]');
                const lastModelMessage = messageElements[messageElements.length - 1];

                if (lastModelMessage) {
                    lastModelMessage.scrollIntoView({ block: 'start', behavior: 'smooth' });
                } else {
                    container.scrollTop = container.scrollHeight;
                }
            }
        });
    }
    lastIsLoading.current = isLoading;
  }, [isLoading]);


  // 5. The Sticky Loop (Bottom Tracking during loading)
  // This runs continuously while isLoading is true for network phase
  useEffect(() => {
    if (!isLoading) {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
      return;
    }

    const loop = () => {
      const container = scrollContainerRef.current;
      if (container && !isUserScrolledUp.current) {
        const { scrollHeight, scrollTop, clientHeight } = container;
        const distanceFromBottom = scrollHeight - (scrollTop + clientHeight);

        // Sticky logic: If content pushes down, follow it, but allow the "Snap to Top" gap
        // We only force scroll if the bottom is obscured by more than threshold
        if (distanceFromBottom > 20) {
            container.scrollTop = scrollHeight - clientHeight;
        }
      }
      scrollRafId.current = requestAnimationFrame(loop);
    };

    loop();

    return () => {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
    };
  }, [isLoading]);

  // 6. Fallback: Handle non-streaming loads
  useLayoutEffect(() => {
    if (!isLoading && scrollContainerRef.current && !isUserScrolledUp.current) {
       scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [messages.length, isLoading]);

  useEffect(() => {
    return () => {
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    };
  }, [messages]);

  const startEditing = (msg: Message) => { 
    setEditingId(msg.id); 
    setConfirmDeleteId(null);
  };

  // Calculate styles for loading bubble to match ChatMessage model bubbles
  const borderAlpha = 0.5 + (bubbleTransparency / 100) * 0.5;
  const loadingBubbleStyle = {
      backgroundColor: `rgba(var(--color-theme-primary-rgb), ${(bubbleTransparency / 100) * 0.15})`,
      borderColor: isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`
  };

  const showLoadingAvatar = avatarVisibility === 'always' || avatarVisibility === 'model-only';

  if (messages.length === 0) {
    return (
      <div className="empty-state">
        <div className="kirby-logo-large animate-fade-in-up">
            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
        </div>
        <h1 className="welcome-title">{t('app.title', language)}</h1>
        <p className="welcome-desc">{t('msg.welcome_desc', language)}</p>
      </div>
    );
  }

  return (
    <div 
        ref={scrollContainerRef}
        onScroll={handleScroll}
        className="chat-interface-container"
    >
      <div className="messages-wrapper">
        {messages.map((msg, index) => (
            <div key={msg.id} data-role={msg.role}>
                <ChatMessage
                    msg={msg}
                    isEditing={editingId === msg.id}
                    isConfirmingDelete={confirmDeleteId === msg.id}
                    isLoading={isLoading}
                    bubbleTransparency={bubbleTransparency}
                    textWrapping={textWrapping}
                    fontSize={fontSize}
                    showModelName={showModelName}
                    showResponseTimer={showResponseTimer}
                    language={language}
                    theme={theme}
                    kirbyThemeColor={kirbyThemeColor}
                    onEditMessage={onEditMessage}
                    onDeleteMessage={onDeleteMessage}
                    onRegenerate={onRegenerate}
                    onTranslate={onTranslate}
                    setEditingId={setEditingId}
                    setConfirmDeleteId={setConfirmDeleteId}
                    startEditing={startEditing}
                    deleteTimerRef={deleteTimerRef}
                    onShowToast={onShowToast}
                    smoothAnimation={smoothAnimation}
                    isLast={index === messages.length - 1}
                    onScrollToBottom={scrollToBottom}
                    avatarVisibility={avatarVisibility}
                />
            </div>
        ))}

        {isLoading && (
            <div className={`loading-indicator ${containerClass} animate-fade-in-up`} data-role="loading">
            <div className="flex gap-3">
                {showLoadingAvatar && (
                    <div className="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center overflow-hidden">
                        <div className="w-full h-full scale-150">
                            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
                        </div>
                    </div>
                )}
                <div 
                    className="loading-bubble"
                    style={loadingBubbleStyle}
                >
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                    {showResponseTimer && <LoadingTimer />}
                </div>
            </div>
            </div>
        )}

        {/* Dynamic Bottom Buffer */}
        <div 
            className="w-full transition-all duration-300 ease-out flex-shrink-0" 
            style={{ height: isLoading ? '160px' : '0px' }} 
            aria-hidden="true" 
        />
      </div>
    </div>
  );
};

export default ChatInterface;

"use client";

import React, { useState, useEffect, useRef } from 'react';
import { X, Settings, Download, Upload, Sliders, RotateCw, Shield, Github, CheckCircle } from 'lucide-react';
import { AppSettings, KeyConfig, DialogConfig, APP_VERSION, ModelInfo } from '../../types';
import { LLMService } from '../../services/llmService';
import { t } from '../../utils/i18n';
import { GeneralAppearanceSettings } from './GeneralAppearanceSettings';
import { ModelParameterSettings } from './ModelParameterSettings';
import { ApiKeyManagement } from './ApiKeyManagement';
import { SystemPromptManagement } from './SystemPromptManagement';
import { SecuritySettings } from './SecuritySettings';
import { CollapsibleSection } from './CollapsibleSection';
import { ScriptFilterSettings } from './ScriptFilterSettings';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  apiKeys: KeyConfig[];
  onUpdateKeys: (keys: KeyConfig[]) => void;
  settings: AppSettings;
  onUpdateSettings: (settings: AppSettings) => void;
  llmService: LLMService | null;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  onShowDialog: (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => void;
  knownModels: ModelInfo[];
  onUpdateKnownModels: (models: ModelInfo[]) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  apiKeys,
  onUpdateKeys,
  settings,
  onUpdateSettings,
  llmService,
  onShowToast,
  onShowDialog,
  knownModels,
  onUpdateKnownModels
}) => {
  const [localKeys, setLocalKeys] = useState<KeyConfig[]>([]);
  const [localSettings, setLocalSettings] = useState<AppSettings>(settings);
  const [localKnownModels, setLocalKnownModels] = useState<ModelInfo[]>(knownModels);
  const [activeTab, setActiveTab] = useState<'general' | 'apikeys' | 'model' | 'security'>('general');
  const lang = localSettings.language;
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize local state
  useEffect(() => {
    if (isOpen) {
      setLocalKeys(JSON.parse(JSON.stringify(apiKeys || []))); 
      setLocalSettings(JSON.parse(JSON.stringify(settings || {})));
      setLocalKnownModels(JSON.parse(JSON.stringify(knownModels || [])));
    }
  }, [isOpen, apiKeys, settings, knownModels]);

  // --- Theme Preview Logic ---
  useEffect(() => {
    if (!isOpen) return;
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');

    root.classList.add(`theme-${localSettings.theme}`);
    if (['dark', 'twilight', 'vscode-dark'].includes(localSettings.theme)) {
        root.classList.add('dark');
    }
  }, [localSettings.theme, isOpen]);

  const handleCloseOrCancel = () => {
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');

    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark'].includes(settings.theme)) {
        root.classList.add('dark');
    }
    onClose();
  };

  const handleSave = () => {
    onUpdateKeys(localKeys);
    onUpdateSettings(localSettings);
    onUpdateKnownModels(localKnownModels);
    onClose();
  };

  // --- Config Export/Import ---
  const handleExportSettings = () => {
    // Ensure knownModels is not included in the export
    const settingsToExport = { ...localSettings };
    // @ts-ignore - Handle legacy property if present during runtime
    if (settingsToExport.knownModels) delete settingsToExport.knownModels;

    const data = {
      version: 4,
      type: 'omnichat_settings',
      timestamp: new Date().toISOString(),
      keys: localKeys,
      settings: settingsToExport
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `omnichat_config_${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    onShowToast(t('msg.config_exported', lang), 'success');
  };

  const handleImportTrigger = () => {
    fileInputRef.current?.click();
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);
        if (parsed.type === 'omnichat_settings') {
           if (parsed.keys && Array.isArray(parsed.keys)) setLocalKeys(parsed.keys);
           if (parsed.settings) {
               // Filter out knownModels if present in imported file to enforce cache-only behavior
               const importedSettings = { ...parsed.settings };
               if (importedSettings.knownModels) delete importedSettings.knownModels;
               setLocalSettings({ ...localSettings, ...importedSettings });
           }
           onShowToast(t('success.settings_import', lang), 'success');
        } else {
           onShowToast(t('msg.invalid_format', lang), 'error');
        }
      } catch (err) {
        console.error(err);
        onShowToast(t('error.load_file', lang), 'error');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  if (!isOpen) return null;

  const tabs = [
    { id: 'general', icon: <Sliders className="w-4 h-4"/>, label: t('settings.general', lang) },
    { id: 'apikeys', icon: <Key className="w-4 h-4"/>, label: t('settings.api_keys', lang) },
    { id: 'model', icon: <RotateCw className="w-4 h-4"/>, label: t('settings.ai_parameters', lang) },
    { id: 'security', icon: <Shield className="w-4 h-4"/>, label: t('settings.security', lang) }
  ];

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm md:p-4 p-0 animate-fade-in-up" role="dialog" aria-modal="true" aria-labelledby="settings-modal-title">
      <div className={`bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 md:rounded-2xl rounded-none w-full md:max-w-3xl h-full md:h-auto md:max-h-[90vh] shadow-2xl flex flex-col`}>

        {/* Header */}
        <div className="flex items-center justify-between md:p-5 px-4 py-3 border-b border-gray-200 dark:border-gray-800 flex-shrink-0 bg-gray-50/50 dark:bg-gray-900/50 rounded-t-2xl">
          <h2 id="settings-modal-title" className="text-xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <div className="p-2 bg-primary-100 dark:bg-primary-900/30 rounded-lg">
                <Settings className="w-5 h-5 text-primary-600 dark:text-primary-400" />
            </div>
            {t('settings.title', lang)}
          </h2>
          <button onClick={handleCloseOrCancel} className="p-2 text-gray-500 hover:bg-gray-200 dark:hover:bg-gray-800 rounded-lg transition-colors" aria-label={t('action.close_settings', lang)}>
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-200 dark:border-gray-800 md:px-6 px-3 gap-6 overflow-x-auto scrollbar-hide" role="tablist">
            {tabs.map(tab => (
                <button
                    key={tab.id}
                    id={`tab-${tab.id}`}
                    role="tab"
                    aria-controls={`panel-${tab.id}`}
                    aria-selected={activeTab === tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`flex items-center gap-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === tab.id ? 'border-primary-500 text-primary-600 dark:text-primary-400' : 'border-transparent text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
                    aria-label={tab.label}
                >
                    {tab.icon}
                    {tab.label}
                </button>
            ))}
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto md:p-6 px-4 py-3 scrollbar-hide bg-gray-50/30 dark:bg-black/20">

          {/* General Tab */}
          {activeTab === 'general' && (
            <div role="tabpanel" id="panel-general" aria-labelledby="tab-general" className="space-y-4">

                <GeneralAppearanceSettings 
                    settings={localSettings} 
                    onUpdateSettings={setLocalSettings} 
                    lang={lang} 
                />

                {/* Script Filters */}
                <ScriptFilterSettings 
                    settings={localSettings}
                    onUpdateSettings={setLocalSettings}
                    lang={lang}
                    onShowToast={onShowToast}
                />

                {/* Config Management */}
                <CollapsibleSection id="config-management" title={t('settings.manage', lang)} lang={lang}>
                    <div className="grid grid-cols-2 gap-3">
                        <button 
                            onClick={handleExportSettings} 
                            className={`flex items-center justify-center gap-2 px-4 py-2.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 rounded-lg text-sm font-medium text-gray-700 dark:text-gray-200 transition-colors shadow-sm`}
                            aria-label={t('action.export_app_settings', lang)}
                        >
                            <Download className="w-4 h-4" />{t('action.export_settings', lang)}
                        </button>
                        <button 
                            onClick={handleImportTrigger} 
                            className={`flex items-center justify-center gap-2 px-4 py-2.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 rounded-lg text-sm font-medium text-gray-700 dark:text-gray-200 transition-colors shadow-sm`}
                            aria-label={t('action.import_app_settings', lang)}
                        >
                            <Upload className="w-4 h-4" />{t('action.import_settings', lang)}
                        </button>
                        <input type="file" ref={fileInputRef} onChange={handleImportFile} accept=".json" className="hidden" aria-label={t('action.select_config_file', lang)} />
                    </div>
                </CollapsibleSection>

                {/* About & Open Source */}
                <CollapsibleSection id="about" title={t('settings.about', lang)} lang={lang}>
                  <div className="flex flex-col gap-3 text-sm text-gray-600 dark:text-gray-400">
