    }

    const loadedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    if (loadedSettings) {
        setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(loadedSettings) });
    }

    const loadedModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (loadedModels) {
        setKnownModels(JSON.parse(loadedModels));
    }
  }, []);

  // Save Keys
  useEffect(() => {
      if (apiKeys.length > 0) {
        localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
      }
  }, [apiKeys]);

  // Save Settings
  useEffect(() => {
     localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
     // Apply theme to document
     const root = document.documentElement;
     root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');
     root.classList.add(`theme-${settings.theme}`);
     if (['dark', 'twilight', 'vscode-dark'].includes(settings.theme)) {
         root.classList.add('dark');
     }
  }, [settings]);

  // Save Known Models
  useEffect(() => {
     if (knownModels.length > 0) {
         localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
     }
  }, [knownModels]);

  // Load Sessions
  useEffect(() => {
    const loadedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const lastSessionId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (loadedSessions) {
      const parsedSessions: ChatSession[] = JSON.parse(loadedSessions);
      setSessions(parsedSessions);

      if (lastSessionId && parsedSessions.some(s => s.id === lastSessionId)) {
        setActiveSessionId(lastSessionId);
        const session = parsedSessions.find(s => s.id === lastSessionId);
        if (session) setMessages(session.messages);
      } else {
        handleNewChat(parsedSessions);
      }
    } else {
        handleNewChat([]);
    }
  }, []);

  // Save Sessions on change
  useEffect(() => {
      if (sessions.length > 0) {
          localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
      }
      if (activeSessionId) {
          localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
      }
  }, [sessions, activeSessionId]);

  // Security Check
  useEffect(() => {
      if (settings.security.enabled) {
          const now = Date.now();
          const lastLogin = settings.security.lastLogin || 0;
          const duration = (settings.security.lockoutDurationSeconds || 86400) * 1000;

          if (now - lastLogin > duration) {
              setIsLocked(true);
          }
      }
  }, [settings.security]);


  // Initialize LLM Service
  useEffect(() => {
      llmServiceRef.current = new LLMService(apiKeys, (id, code) => {
          // Auto-disable key callback
          setApiKeys(prev => prev.map(k => k.id === id ? { ...k, isActive: false, lastErrorCode: code } : k));
          showToast(t('error.key_auto_disabled', settings.language), 'error');
      });
  }, [apiKeys, settings.language, showToast]);


  // --- Logic Handlers ---

  const handleNewChat = (currentSessions = sessions) => {
    if (isLoading) return;
    const newSession: ChatSession = {
      id: uuidv4(),
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    const updatedSessions = [newSession, ...currentSessions];
    setSessions(updatedSessions);
    setActiveSessionId(newSession.id);
    setMessages([]);
    if (window.innerWidth < 768) setIsMobileMenuOpen(false);
  };

  const handleSelectSession = (id: string) => {
      if (isLoading && id !== activeSessionId) return;
      const session = sessions.find(s => s.id === id);
      if (session) {
          setActiveSessionId(id);
          setMessages(session.messages);
          if (window.innerWidth < 768) setIsMobileMenuOpen(false);
      }
  };

  const handleDeleteSession = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      const updatedSessions = sessions.filter(s => s.id !== id);
      setSessions(updatedSessions);

      if (activeSessionId === id) {
          if (updatedSessions.length > 0) {
              handleSelectSession(updatedSessions[0].id);
          } else {
              handleNewChat(updatedSessions);
          }
      }
  };

  const handleClearChat = () => {
     showDialog({
         type: 'confirm',
         title: t('action.clear_chat', settings.language),
         message: t('msg.confirm_clear_chat', settings.language),
         onConfirm: () => {
             setMessages([]);
             updateCurrentSession([]);
         }
     });
  };

  const updateCurrentSession = (updatedMessages: Message[], newTitle?: string) => {
      setSessions(prev => prev.map(s => {
          if (s.id === activeSessionId) {
              return { 
                  ...s, 
                  messages: updatedMessages,
                  title: newTitle || s.title 
              };
          }
          return s;
      }));
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const constructSystemInstruction = () => {
      const activePrompts = settings.systemPrompts.filter(p => p.isActive);
      return activePrompts.length > 0 
        ? activePrompts.map(p => p.content).join('\n\n') 
        : undefined;
  };

  const applyInputFilter = (text: string) => {
      if (settings.scripts.inputFilterEnabled && settings.scripts.inputFilterCode) {
          try {
              return executeFilterScript(
                  settings.scripts.inputFilterCode, 
                  text, 
                  { role: 'user', history: messages }
              );
          } catch (e) {
              console.error("Input filter failed", e);
              return text;
          }
      }
      return text;
  };

  const applyOutputFilter = (text: string) => {
      if (settings.scripts.outputFilterEnabled && settings.scripts.outputFilterCode) {
          try {
              return executeFilterScript(
                  settings.scripts.outputFilterCode, 
                  text, 
                  { role: 'model', history: messages }
              );
          } catch (e) {
               console.error("Output filter failed", e);
               return text;
          }
      }
      return text;
  };

  const handleSendMessage = async (customMessage?: string) => {
    const textToSend = customMessage || input;
    if ((!textToSend.trim() && !customMessage) || isLoading) return;

    if (!apiKeys.some(k => k.isActive)) {
        showToast(t('error.no_active_keys', settings.language), 'error');
        return;
    }

    const processedInput = applyInputFilter(textToSend);

    // Clear input if strictly user typing
    if (!customMessage) setInput('');

    const newUserMsg: Message = {
        id: uuidv4(),
        role: Role.USER,
        text: processedInput, // Display processed input? Or original? Usually processed is what is sent.
        timestamp: Date.now()
    };

    const updatedMessages = [...messages, newUserMsg];
    setMessages(updatedMessages);
    updateCurrentSession(updatedMessages);
    setIsLoading(true);

    // Placeholder for AI response
    const newAiMsgId = uuidv4();
    const newAiMsg: Message = {
        id: newAiMsgId,
        role: Role.MODEL,
        text: '', // Start empty
        timestamp: Date.now(),
        provider: 'google' // Default, updated later
    };

    setMessages(prev => [...prev, newAiMsg]);

    // Prepare AbortController
    abortControllerRef.current = new AbortController();

    // Prepare History (limit context if needed)
    let historyToSend = updatedMessages.slice(0, -1); // Exclude the just added user message (streamChatResponse adds it via arg)
    // Actually LLMService streamChatResponse expects 'history' and 'newMessage'.
    // And if `historyContextLimit` is set, truncate history.
    if (settings.historyContextLimit > 0) {
        historyToSend = historyToSend.slice(-settings.historyContextLimit);
    }

    // Strip thoughts from history if enabled
    if (settings.generation.stripThoughts) {
        historyToSend = historyToSend.map(m => ({
            ...m,
            text: m.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim()
        }));
    }

    const systemInstruction = constructSystemInstruction();
    const startTime = Date.now();

    try {
        if (!llmServiceRef.current) throw new Error("LLM Service not initialized");

        const response = await llmServiceRef.current.streamChatResponse(
            settings.defaultModel, // Global default if key has no specific model (mostly overridden by key config)
            historyToSend,
            processedInput,
            systemInstruction,
            settings.generation,
            (chunkText) => {
                // Apply Output Filter on chunk (partial) - optional/advanced, usually better on full text or UI render
                // For simplicity, we just update state. 
                // Advanced: apply output filter to full accumulated text? 
                // Let's do a simple pass:
                const filteredChunk = applyOutputFilter(chunkText); 

                setMessages(prev => prev.map(msg => 
                    msg.id === newAiMsgId ? { ...msg, text: filteredChunk } : msg
                ));
            },
            abortControllerRef.current.signal,
            settings.language
        );

        // Final Update with metadata
        const finalText = applyOutputFilter(response.text);

        setMessages(prev => prev.map(msg => 
            msg.id === newAiMsgId ? { 
                ...msg, 
                text: finalText,
                keyIndex: response.usedKeyIndex,
                provider: response.provider,
                model: response.usedModel,
                executionTime: Date.now() - startTime
            } : msg
        ));

        // Update session in storage (async)
        updateCurrentSession([...updatedMessages, { 
            ...newAiMsg, 
            text: finalText, 
            keyIndex: response.usedKeyIndex,
            provider: response.provider,
            model: response.usedModel,
            executionTime: Date.now() - startTime
        }]);

        // Auto-title if it's the first exchange
        if (messages.length === 0) {
            generateTitle(processedInput, finalText);
        }

    } catch (error: any) {
        if (error.message !== 'Aborted by user') {
            const errorMsg = error.message || t('error.unexpected_error', settings.language);
            setMessages(prev => prev.map(msg => 
                msg.id === newAiMsgId ? { ...msg, text: errorMsg, isError: true } : msg
            ));
            showToast(errorMsg, 'error');
        } else {
             // Handle Abort (maybe remove partial message or keep it?)
             // Currently keeping partial
        }
    } finally {
        setIsLoading(false);
        abortControllerRef.current = null;
    }
  };

  const generateTitle = async (userText: string, aiText: string) => {
      // Logic to generate title
      // We can use a separate call or simple heuristic
      // For now, let's just use first few words of user text
      const newTitle = userText.slice(0, 30) + (userText.length > 30 ? '...' : '');
      updateCurrentSession(messages, newTitle); // This might be stale 'messages', better use functional update in setSessions if possible or just update the title directly in sessions

      setSessions(prev => prev.map(s => 
          s.id === activeSessionId ? { ...s, title: newTitle } : s
      ));
  };

  const handleSummarizeTitle = async () => {
      if (!messages.length || isSummarizing) return;
      setIsSummarizing(true);

      const prompt = t('msg.summarize_prompt', settings.language);
      const conversation = messages.slice(-4).map(m => `${m.role}: ${m.text}`).join('\n'); // Last 4 messages

      try {
          // Use a non-streaming call or simple stream
          if (!llmServiceRef.current) throw new Error("Service unavailable");

          // Use a temporary generation config for summary
          const summaryConfig = { ...settings.generation, stream: false, maxOutputTokens: 50 };

          const response = await llmServiceRef.current.streamChatResponse(
              settings.defaultModel,
              [],
              `${prompt}\n\n${conversation}`,
              undefined,
              summaryConfig,
              undefined,
              undefined,
              settings.language
          );

          const newTitle = response.text.replace(/^["']|["']$/g, '').trim();
          setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
          showToast('Title updated', 'success');
      } catch (e) {
          showToast(t('msg.summarize_error', settings.language), 'error');
      } finally {
          setIsSummarizing(false);
      }
  };

  const handleRenameSession = () => {
      showDialog({
          type: 'input',
          title: t('msg.rename_chat', settings.language),
          inputValue: sessions.find(s => s.id === activeSessionId)?.title,
          onConfirm: (val) => {
              if (val) {
                  setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: val } : s));
              }
          }
      });
  };

  const handleEditMessage = (id: string, newText: string) => {
      setMessages(prev => {
          const updated = prev.map(m => m.id === id ? { ...m, text: newText } : m);
          updateCurrentSession(updated);
          return updated;
      });
  };

  const handleDeleteMessage = (id: string) => {
      setMessages(prev => {
          const updated = prev.filter(m => m.id !== id);
          updateCurrentSession(updated);
          return updated;
      });
  };

  const handleRegenerate = (id: string) => {
      // Find the message index
      const index = messages.findIndex(m => m.id === id);
      if (index === -1) return;

      // If it's a Model message, we want to regenerate IT. 
      // Context is everything before it. Last user message is the one before it.
      // If it's a User message, we want to regenerate response TO IT.

      let historyToKeep: Message[] = [];
      let promptToUse = "";

      if (messages[index].role === Role.MODEL) {
          // It's a model response we want to redo
          // Remove this message and everything after it
          historyToKeep = messages.slice(0, index);
          // The prompt is the last user message in 'historyToKeep' ?? 
          // Actually logic: streamChatResponse expects 'history' (previous turns) and 'newMessage' (latest user prompt)

          const lastUserMsg = historyToKeep[historyToKeep.length - 1];
          if (!lastUserMsg || lastUserMsg.role !== Role.USER) {
               showToast("Cannot regenerate: No user prompt found.", 'error');
               return;
          }

          // Remove last user message from history because it will be passed as 'newMessage'
          historyToKeep = historyToKeep.slice(0, -1);
          promptToUse = lastUserMsg.text;

      } else {
          // It's a user message, we want to regenerate the response AFTER it
          // Remove everything after this user message
          historyToKeep = messages.slice(0, index); 
          promptToUse = messages[index].text;
      }

      // Update UI state to remove old messages
      // We need to re-add the user prompt if we sliced it out? 
      // Actually handleSendMessage adds the user message.

      // Strategy: Update messages state to 'historyToKeep', then call handleSendMessage(promptToUse)
      // BUT handleSendMessage appends the user message. 

      // So setMessages to historyToKeep
      setMessages(historyToKeep);
      // Update session
      updateCurrentSession(historyToKeep);

      // Call send
      handleSendMessage(promptToUse);
  };

  const handleTranslate = async (id: string) => {
      // Find message
      const msg = messages.find(m => m.id === id);
      if (!msg) return;

      const prompt = `Translate the following text to Simplified Chinese. Maintain format. Text:\n${msg.text}`;

      // We don't change chat history, we just generate a new response appended? 
      // Or replace? 
      // Usually users expect a new message with translation.
      handleSendMessage(prompt);
  };

  const handleUnlock = () => {
      setIsLocked(false);
      setSettings(prev => ({ ...prev, security: { ...prev.security, lastLogin: Date.now() } }));
  };

  // --- Render ---

  if (isLocked) {
      return (
          <Suspense fallback={<div className="flex items-center justify-center h-screen bg-gray-100 dark:bg-gray-900">Loading...</div>}>
             <SecurityLock 
                config={settings.security}
                onUnlock={handleUnlock}
                lang={settings.language}
                theme={settings.theme}
                kirbyThemeColor={settings.kirbyThemeColor}
             />
          </Suspense>
      );
  }

  return (
    <div className={`app-container flex h-screen bg-white dark:bg-gray-950 overflow-hidden transition-colors duration-300 theme-${settings.theme}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialogConfig} onClose={() => setDialogConfig(prev => ({ ...prev, isOpen: false }))} lang={settings.language} />

      {/* Sidebar (Desktop) */}
      <div className="hidden md:flex flex-shrink-0">
        <Sidebar 
            sessions={sessions}
            activeSessionId={activeSessionId}
            activeKeysCount={apiKeys.filter(k => k.isActive).length}
            language={settings.language}
            theme={settings.theme}
            kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => handleNewChat()}
            onSelectSession={handleSelectSession}
            onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
         <Header 
            currentSessionTitle={sessions.find(s => s.id === activeSessionId)?.title || t('msg.new_chat_title', settings.language)}
            isSummarizing={isSummarizing}
            hasMessages={messages.length > 0}
            language={settings.language}
            onRename={handleRenameSession}
            onSummarize={handleSummarizeTitle}
            onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
            onNewChat={() => handleNewChat()}
            onClearChat={handleClearChat}
            onOpenSettings={() => setIsSettingsOpen(true)}
            onSaveChat={() => {
                const session = sessions.find(s => s.id === activeSessionId);
                if (!session) return;
                const blob = new Blob([JSON.stringify(session, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `chat_${session.title.slice(0,20).replace(/\s+/g,'_')}_${new Date().toISOString().slice(0,10)}.json`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
            }}
            onLoadSession={(msgs, title) => {
                const newSession: ChatSession = {
                    id: uuidv4(),
                    title: title || 'Imported Chat',
                    messages: msgs,
                    createdAt: Date.now()
                };
                setSessions(prev => [newSession, ...prev]);
                setActiveSessionId(newSession.id);
                setMessages(msgs);
                showToast(t('success.chat_import', settings.language), 'success');
            }}
            onShowToast={showToast}
         />

         <main className="flex-1 overflow-hidden relative flex flex-col">
            <ChatInterface 
                messages={messages}
                isLoading={isLoading}
                onEditMessage={handleEditMessage}
                onDeleteMessage={handleDeleteMessage}
                onRegenerate={handleRegenerate}
                onTranslate={handleTranslate}
                language={settings.language}
                fontSize={settings.fontSize}
                textWrapping={settings.textWrapping}
                bubbleTransparency={settings.bubbleTransparency}
                showModelName={settings.showModelName}
                showResponseTimer={settings.showResponseTimer}
                theme={settings.theme}
                kirbyThemeColor={settings.kirbyThemeColor}
                onShowToast={showToast}
                smoothAnimation={settings.smoothAnimation}
                avatarVisibility={settings.avatarVisibility}
            />

            <div className="flex-shrink-0 relative z-10">
                <ChatInput 
                    input={input}
                    setInput={setInput}
                    onSend={() => handleSendMessage()}
                    onStop={handleStopGeneration}
                    isLoading={isLoading}
                    isDisabled={apiKeys.filter(k => k.isActive).length === 0}
                    fontSize={settings.fontSize}
                    language={settings.language}
                    activeKeysCount={apiKeys.filter(k => k.isActive).length}
                    showTokenUsage={settings.showTokenUsage}
                    history={messages}
                    historyLimit={settings.historyContextLimit}
                    theme={settings.theme}
                    onGetTokenCount={async (text) => {
                         // Find active key to use for counting
                         const activeKey = apiKeys.find(k => k.isActive && k.provider === 'google');
                         if (!activeKey || !llmServiceRef.current) return -1;
                         return await llmServiceRef.current.countTokens(activeKey, messages, text, undefined);
                    }}
                />
            </div>
         </main>
      </div>

      {/* Mobile Menu */}
      <Suspense fallback={null}>
         <MobileMenu 
            isOpen={isMobileMenuOpen}
            sessions={sessions}
            activeSessionId={activeSessionId}
            language={settings.language}
            onClose={() => setIsMobileMenuOpen(false)}
            onNewChat={() => handleNewChat()}
            onSelectSession={handleSelectSession}
            onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
         />
      </Suspense>

      {/* Settings Modal */}
      <Suspense fallback={null}>
         <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            apiKeys={apiKeys}
            onUpdateKeys={setApiKeys}
            settings={settings}
            onUpdateSettings={setSettings}
            llmService={llmServiceRef.current}
            onShowToast={showToast}
            onShowDialog={showDialog}
            knownModels={knownModels}
            onUpdateKnownModels={setKnownModels}
         />
      </Suspense>

    </div>
  );
};

export default App;

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo, ScriptConfig } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

// Lazy load heavy or hidden-by-default components
const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

// --- Default Configuration ---
const DEFAULT_MODEL = GeminiModel.FLASH;
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-2.5-flash', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-2.5-flash-thinking-preview-01-21', inputTokenLimit: 1048576, outputTokenLimit: 8192 }
];

const DEFAULT_SETTINGS: AppSettings = {
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light',
    language: 'en',
    fontSize: 14,
    textWrapping: 'default',
    avatarVisibility: 'always',
    bubbleTransparency: 100,
    showModelName: true,
    kirbyThemeColor: false,
    showTokenUsage: true,
    showResponseTimer: true,
    smoothAnimation: true,
    historyContextLimit: 0,
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now()
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: true,
        thinkingBudget: 0,
        stripThoughts: false
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    }
};

const App: React.FC = () => {
  // State Initialization
  const [messages, setMessages] = useState<Message[]>([]);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string>('');
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSummarizing, setIsSummarizing] = useState(false);

  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocked, setIsLocked] = useState(false);

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialogConfig, setDialogConfig] = useState<DialogConfig>({
    isOpen: false,
    type: 'alert',
    title: '',
    onConfirm: () => {}
  });

  const llmServiceRef = useRef<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // Toast Handler
  const showToast = useCallback((message: string, type: 'success' | 'error' | 'info') => {
    setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  // Dialog Handler
  const showDialog = useCallback((config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
    setDialogConfig({
      isOpen: true,
      type: config.type || 'alert',
      title: config.title,
      message: config.message,
      inputValue: config.inputValue,
      inputPlaceholder: config.inputPlaceholder,
      onConfirm: config.onConfirm,
      onCancel: () => setDialogConfig(prev => ({ ...prev, isOpen: false }))
    });
  }, []);

  // --- Initialization & Storage Effects ---

  // Load Settings & Keys & Models
  useEffect(() => {
    const loadedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    if (loadedKeys) {
       setApiKeys(JSON.parse(loadedKeys));
    } else if (ENV_KEY) {
       setApiKeys([{
         id: uuidv4(),
         key: ENV_KEY,
         provider: 'google',
         isActive: true,
         usageLimit: 100,
         isRateLimited: false,
         lastUsed: 0,
         model: DEFAULT_MODEL
       }]);
    }

    const loadedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    if (loadedSettings) {
        setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(loadedSettings) });
    }

    const loadedModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (loadedModels) {
        setKnownModels(JSON.parse(loadedModels));
    }
  }, []);

  // Save Keys
  useEffect(() => {
      if (apiKeys.length > 0) {
        localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
      }
  }, [apiKeys]);

  // Save Settings
  useEffect(() => {
     localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
     const root = document.documentElement;
     root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');
     root.classList.add(`theme-${settings.theme}`);
     if (['dark', 'twilight', 'vscode-dark'].includes(settings.theme)) {
         root.classList.add('dark');
     }
  }, [settings]);

  // Save Known Models
  useEffect(() => {
     if (knownModels.length > 0) {
         localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
     }
  }, [knownModels]);

  // Load Sessions
  useEffect(() => {
    const loadedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const lastSessionId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (loadedSessions) {
      const parsedSessions: ChatSession[] = JSON.parse(loadedSessions);
      setSessions(parsedSessions);

      if (lastSessionId && parsedSessions.some(s => s.id === lastSessionId)) {
        setActiveSessionId(lastSessionId);
        const session = parsedSessions.find(s => s.id === lastSessionId);
        if (session) setMessages(session.messages);
      } else {
        handleNewChat(parsedSessions);
      }
    } else {
        handleNewChat([]);
    }
  }, []);

  // Save Sessions on change
  useEffect(() => {
      if (sessions.length > 0) {
          localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
      }
      if (activeSessionId) {
          localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
      }
  }, [sessions, activeSessionId]);

  // Security Check
  useEffect(() => {
      if (settings.security.enabled) {
          const now = Date.now();
          const lastLogin = settings.security.lastLogin || 0;
          const duration = (settings.security.lockoutDurationSeconds || 86400) * 1000;

          if (now - lastLogin > duration) {
              setIsLocked(true);
          }
      }
  }, [settings.security]);


  // Initialize LLM Service
  useEffect(() => {
      llmServiceRef.current = new LLMService(apiKeys, (id, code) => {
          setApiKeys(prev => prev.map(k => k.id === id ? { ...k, isActive: false, lastErrorCode: code } : k));
          showToast(t('error.key_auto_disabled', settings.language), 'error');
      });
  }, [apiKeys, settings.language, showToast]);


  // --- Logic Handlers ---

  const handleNewChat = (currentSessions = sessions) => {
    if (isLoading) return;
    const newSession: ChatSession = {
      id: uuidv4(),
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    const updatedSessions = [newSession, ...currentSessions];
    setSessions(updatedSessions);
    setActiveSessionId(newSession.id);
    setMessages([]);
    if (window.innerWidth < 768) setIsMobileMenuOpen(false);
  };

  const handleSelectSession = (id: string) => {
      if (isLoading && id !== activeSessionId) return;
      const session = sessions.find(s => s.id === id);
      if (session) {
          setActiveSessionId(id);
          setMessages(session.messages);
          if (window.innerWidth < 768) setIsMobileMenuOpen(false);
      }
  };

  const handleDeleteSession = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      const updatedSessions = sessions.filter(s => s.id !== id);
      setSessions(updatedSessions);

      if (activeSessionId === id) {
          if (updatedSessions.length > 0) {
              handleSelectSession(updatedSessions[0].id);
          } else {
              handleNewChat(updatedSessions);
          }
      }
  };

  const handleClearChat = () => {
     showDialog({
         type: 'confirm',
         title: t('action.clear_chat', settings.language),
         message: t('msg.confirm_clear_chat', settings.language),
         onConfirm: () => {
             setMessages([]);
             updateCurrentSession([]);
         }
     });
  };

  const updateCurrentSession = (updatedMessages: Message[], newTitle?: string) => {
      setSessions(prev => prev.map(s => {
          if (s.id === activeSessionId) {
              return { 
                  ...s, 
                  messages: updatedMessages,
                  title: newTitle || s.title 
              };
          }
          return s;
      }));
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const constructSystemInstruction = () => {
      const activePrompts = settings.systemPrompts.filter(p => p.isActive);
      return activePrompts.length > 0 
        ? activePrompts.map(p => p.content).join('\n\n') 
        : undefined;
  };

  const applyInputFilter = (text: string) => {
      if (settings.scripts.inputFilterEnabled && settings.scripts.inputFilterCode) {
          try {
              return executeFilterScript(
                  settings.scripts.inputFilterCode, 
                  text, 
                  { role: 'user', history: messages }
              );
          } catch (e) {
              console.error("Input filter failed", e);
              return text;
          }
      }
      return text;
  };

  const applyOutputFilter = (text: string) => {
      if (settings.scripts.outputFilterEnabled && settings.scripts.outputFilterCode) {
          try {
              return executeFilterScript(
                  settings.scripts.outputFilterCode, 
                  text, 
                  { role: 'model', history: messages }
              );
          } catch (e) {
               console.error("Output filter failed", e);
               return text;
          }
      }
      return text;
  };

  const handleSendMessage = async (customMessage?: string) => {
    const textToSend = customMessage || input;
    if ((!textToSend.trim() && !customMessage) || isLoading) return;

    if (!apiKeys.some(k => k.isActive)) {
        showToast(t('error.no_active_keys', settings.language), 'error');
        return;
    }

    const processedInput = applyInputFilter(textToSend);

    // Clear input if strictly user typing
    if (!customMessage) setInput('');

    const newUserMsg: Message = {
        id: uuidv4(),
        role: Role.USER,
        text: processedInput,
        timestamp: Date.now()
    };

    const updatedMessages = [...messages, newUserMsg];
    setMessages(updatedMessages);
    updateCurrentSession(updatedMessages);
    setIsLoading(true);

    // Placeholder for AI response
    const newAiMsgId = uuidv4();
    const newAiMsg: Message = {
        id: newAiMsgId,
        role: Role.MODEL,
        text: '', // Start empty
        timestamp: Date.now(),
        provider: 'google' // Default
    };

    setMessages(prev => [...prev, newAiMsg]);

    abortControllerRef.current = new AbortController();

    // Prepare History (limit context if needed)
    let historyToSend = updatedMessages.slice(0, -1);

    if (settings.historyContextLimit > 0) {
        historyToSend = historyToSend.slice(-settings.historyContextLimit);
    }

    if (settings.generation.stripThoughts) {
        historyToSend = historyToSend.map(m => ({
            ...m,
            text: m.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim()
        }));
    }

    const systemInstruction = constructSystemInstruction();
    const startTime = Date.now();

    try {
        if (!llmServiceRef.current) throw new Error("LLM Service not initialized");

        const response = await llmServiceRef.current.streamChatResponse(
            settings.defaultModel, 
            historyToSend,
            processedInput,
            systemInstruction,
            settings.generation,
            (chunkText) => {
                const filteredChunk = applyOutputFilter(chunkText); 
                setMessages(prev => prev.map(msg => 
                    msg.id === newAiMsgId ? { ...msg, text: filteredChunk } : msg
                ));
            },
            abortControllerRef.current.signal,
            settings.language
        );

        const finalText = applyOutputFilter(response.text);

        setMessages(prev => prev.map(msg => 
            msg.id === newAiMsgId ? { 
                ...msg, 
                text: finalText,
                keyIndex: response.usedKeyIndex,
                provider: response.provider,
                model: response.usedModel,
                executionTime: Date.now() - startTime
            } : msg
        ));

        updateCurrentSession([...updatedMessages, { 
            ...newAiMsg, 
            text: finalText, 
            keyIndex: response.usedKeyIndex,
            provider: response.provider,
            model: response.usedModel,
            executionTime: Date.now() - startTime
        }]);

        if (messages.length === 0) {
            generateTitle(processedInput, finalText);
        }

    } catch (error: any) {
        if (error.message !== 'Aborted by user') {
            const errorMsg = error.message || t('error.unexpected_error', settings.language);
            setMessages(prev => prev.map(msg => 
                msg.id === newAiMsgId ? { ...msg, text: errorMsg, isError: true } : msg
            ));
            showToast(errorMsg, 'error');
        }
    } finally {
        setIsLoading(false);
        abortControllerRef.current = null;
    }
  };

  const generateTitle = async (userText: string, aiText: string) => {
      const newTitle = userText.slice(0, 30) + (userText.length > 30 ? '...' : '');
      setSessions(prev => prev.map(s => 
          s.id === activeSessionId ? { ...s, title: newTitle } : s
      ));
  };

  const handleSummarizeTitle = async () => {
      if (!messages.length || isSummarizing) return;
      setIsSummarizing(true);

      const prompt = t('msg.summarize_prompt', settings.language);
      const conversation = messages.slice(-4).map(m => `${m.role}: ${m.text}`).join('\n'); // Last 4 messages

      try {
          if (!llmServiceRef.current) throw new Error("Service unavailable");

          const summaryConfig = { ...settings.generation, stream: false, maxOutputTokens: 50 };

          const response = await llmServiceRef.current.streamChatResponse(
              settings.defaultModel,
              [],
              `${prompt}\n\n${conversation}`,
              undefined,
              summaryConfig,
              undefined,
              undefined,
              settings.language
          );

          const newTitle = response.text.replace(/^["']|["']$/g, '').trim();
          setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
          showToast('Title updated', 'success');
      } catch (e) {
          showToast(t('msg.summarize_error', settings.language), 'error');
      } finally {
          setIsSummarizing(false);
      }
  };

  const handleRenameSession = () => {
      showDialog({
          type: 'input',
          title: t('msg.rename_chat', settings.language),
          inputValue: sessions.find(s => s.id === activeSessionId)?.title,
          onConfirm: (val) => {
              if (val) {
                  setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: val } : s));
              }
          }
      });
  };

  const handleEditMessage = (id: string, newText: string) => {
      setMessages(prev => {
          const updated = prev.map(m => m.id === id ? { ...m, text: newText } : m);
          updateCurrentSession(updated);
          return updated;
      });
  };

  const handleDeleteMessage = (id: string) => {
      setMessages(prev => {
          const updated = prev.filter(m => m.id !== id);
          updateCurrentSession(updated);
          return updated;
      });
  };

  const handleRegenerate = (id: string) => {
      const index = messages.findIndex(m => m.id === id);
      if (index === -1) return;

      let historyToKeep: Message[] = [];
      let promptToUse = "";

      if (messages[index].role === Role.MODEL) {
          historyToKeep = messages.slice(0, index);
          const lastUserMsg = historyToKeep[historyToKeep.length - 1];
          if (!lastUserMsg || lastUserMsg.role !== Role.USER) {
               showToast("Cannot regenerate: No user prompt found.", 'error');
               return;
          }
          historyToKeep = historyToKeep.slice(0, -1);
          promptToUse = lastUserMsg.text;
      } else {
          historyToKeep = messages.slice(0, index); 
          promptToUse = messages[index].text;
      }

      setMessages(historyToKeep);
      updateCurrentSession(historyToKeep);
      handleSendMessage(promptToUse);
  };

  const handleTranslate = async (id: string) => {
      const msg = messages.find(m => m.id === id);
      if (!msg) return;

      const prompt = `Translate the following text to Simplified Chinese. Maintain format. Text:\n${msg.text}`;
      handleSendMessage(prompt);
  };

  const handleUnlock = () => {
      setIsLocked(false);
      setSettings(prev => ({ ...prev, security: { ...prev.security, lastLogin: Date.now() } }));
  };

  // --- Render ---

  if (isLocked) {
      return (
          <Suspense fallback={<div className="flex items-center justify-center h-screen bg-gray-100 dark:bg-gray-900">Loading...</div>}>
             <SecurityLock 
                config={settings.security}
                onUnlock={handleUnlock}
                lang={settings.language}
                theme={settings.theme}
                kirbyThemeColor={settings.kirbyThemeColor}
             />
          </Suspense>
      );
  }

  return (
    <div className={`app-container flex h-screen bg-white dark:bg-gray-950 overflow-hidden transition-colors duration-300 theme-${settings.theme}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialogConfig} onClose={() => setDialogConfig(prev => ({ ...prev, isOpen: false }))} lang={settings.language} />

      {/* Sidebar (Desktop) */}
      <div className="hidden md:flex flex-shrink-0">
        <Sidebar 
            sessions={sessions}
            activeSessionId={activeSessionId}
            activeKeysCount={apiKeys.filter(k => k.isActive).length}
            language={settings.language}
            theme={settings.theme}
            kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => handleNewChat()}
            onSelectSession={handleSelectSession}
            onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
         <Header 
            currentSessionTitle={sessions.find(s => s.id === activeSessionId)?.title || t('msg.new_chat_title', settings.language)}
            isSummarizing={isSummarizing}
            hasMessages={messages.length > 0}
            language={settings.language}
            onRename={handleRenameSession}
            onSummarize={handleSummarizeTitle}
            onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
            onNewChat={() => handleNewChat()}
            onClearChat={handleClearChat}
            onOpenSettings={() => setIsSettingsOpen(true)}
            onSaveChat={() => {
                const session = sessions.find(s => s.id === activeSessionId);
                if (!session) return;
                const blob = new Blob([JSON.stringify(session, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `chat_${session.title.slice(0,20).replace(/\s+/g,'_')}_${new Date().toISOString().slice(0,10)}.json`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
            }}
            onLoadSession={(msgs, title) => {
                const newSession: ChatSession = {
                    id: uuidv4(),
                    title: title || 'Imported Chat',
                    messages: msgs,
                    createdAt: Date.now()
                };
                setSessions(prev => [newSession, ...prev]);
                setActiveSessionId(newSession.id);
                setMessages(msgs);
                showToast(t('success.chat_import', settings.language), 'success');
            }}
            onShowToast={showToast}
         />

         <main className="flex-1 overflow-hidden relative flex flex-col">
            <ChatInterface 
                messages={messages}
                isLoading={isLoading}
                onEditMessage={handleEditMessage}
                onDeleteMessage={handleDeleteMessage}
                onRegenerate={handleRegenerate}
                onTranslate={handleTranslate}
                language={settings.language}
                fontSize={settings.fontSize}
                textWrapping={settings.textWrapping}
                bubbleTransparency={settings.bubbleTransparency}
                showModelName={settings.showModelName}
                showResponseTimer={settings.showResponseTimer}
                theme={settings.theme}
                kirbyThemeColor={settings.kirbyThemeColor}
                onShowToast={showToast}
                smoothAnimation={settings.smoothAnimation}
                avatarVisibility={settings.avatarVisibility}
            />

            <div className="flex-shrink-0 relative z-10">
                <ChatInput 
                    input={input}
                    setInput={setInput}
                    onSend={() => handleSendMessage()}
                    onStop={handleStopGeneration}
                    isLoading={isLoading}
                    isDisabled={apiKeys.filter(k => k.isActive).length === 0}
                    fontSize={settings.fontSize}
                    language={settings.language}
                    activeKeysCount={apiKeys.filter(k => k.isActive).length}
                    showTokenUsage={settings.showTokenUsage}
                    history={messages}
                    historyLimit={settings.historyContextLimit}
                    theme={settings.theme}
                    onGetTokenCount={async (text) => {
                         const activeKey = apiKeys.find(k => k.isActive && k.provider === 'google');
                         if (!activeKey || !llmServiceRef.current) return -1;
                         return await llmServiceRef.current.countTokens(activeKey, messages, text, undefined);
                    }}
                />
            </div>
         </main>
      </div>

      {/* Mobile Menu */}
      <Suspense fallback={null}>
         <MobileMenu 
            isOpen={isMobileMenuOpen}
            sessions={sessions}
            activeSessionId={activeSessionId}
            language={settings.language}
            onClose={() => setIsMobileMenuOpen(false)}
            onNewChat={() => handleNewChat()}
            onSelectSession={handleSelectSession}
            onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
         />
      </Suspense>

      {/* Settings Modal */}
      <Suspense fallback={null}>
         <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            apiKeys={apiKeys}
            onUpdateKeys={setApiKeys}
            settings={settings}
            onUpdateSettings={setSettings}
            llmService={llmServiceRef.current}
            onShowToast={showToast}
            onShowDialog={showDialog}
            knownModels={knownModels}
            onUpdateKnownModels={setKnownModels}
         />
      </Suspense>

    </div>
  );
};

export default App;

"use client";

import React, { useState, useEffect, useRef } from 'react';
import { X, Settings, Download, Upload, Sliders, RotateCw, Shield, Github, CheckCircle, Key } from 'lucide-react';
import { AppSettings, KeyConfig, DialogConfig, APP_VERSION, ModelInfo } from '../types';
import { LLMService } from '../services/llmService';
import { t } from '../utils/i18n';
import { GeneralAppearanceSettings } from './settings/GeneralAppearanceSettings';
import { ModelParameterSettings } from './settings/ModelParameterSettings';
import { ApiKeyManagement } from './settings/ApiKeyManagement';
import { SystemPromptManagement } from './settings/SystemPromptManagement';
import { SecuritySettings } from './settings/SecuritySettings';
import { CollapsibleSection } from './settings/CollapsibleSection';
import { ScriptFilterSettings } from './settings/ScriptFilterSettings';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  apiKeys: KeyConfig[];
  onUpdateKeys: (keys: KeyConfig[]) => void;
  settings: AppSettings;
  onUpdateSettings: (settings: AppSettings) => void;
  llmService: LLMService | null;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  onShowDialog: (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => void;
  knownModels: ModelInfo[];
  onUpdateKnownModels: (models: ModelInfo[]) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  apiKeys,
  onUpdateKeys,
  settings,
  onUpdateSettings,
  llmService,
  onShowToast,
  onShowDialog,
  knownModels,
  onUpdateKnownModels
}) => {
  // --- Local State for buffering changes before save ---
  const [localKeys, setLocalKeys] = useState<KeyConfig[]>([]);
  const [localSettings, setLocalSettings] = useState<AppSettings>(settings);
  const [localKnownModels, setLocalKnownModels] = useState<ModelInfo[]>(knownModels);
  const [activeTab, setActiveTab] = useState<'general' | 'apikeys' | 'model' | 'security'>('general');
  const lang = localSettings.language;
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Initialize local state when modal opens ---
  useEffect(() => {
    if (isOpen) {
      setLocalKeys(JSON.parse(JSON.stringify(apiKeys || []))); 
      setLocalSettings(JSON.parse(JSON.stringify(settings || {})));
      setLocalKnownModels(JSON.parse(JSON.stringify(knownModels || [])));
    }
  }, [isOpen, apiKeys, settings, knownModels]);

  // --- Theme Preview Logic (Live preview when changing theme) ---
  useEffect(() => {
    if (!isOpen) return;
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');

    root.classList.add(`theme-${localSettings.theme}`);
    if (['dark', 'twilight', 'vscode-dark'].includes(localSettings.theme)) {
        root.classList.add('dark');
    }
  }, [localSettings.theme, isOpen]);

  // --- Revert changes on Close/Cancel ---
  const handleCloseOrCancel = () => {
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-vscode-light', 'theme-vscode-dark');

    // Restore original theme
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark'].includes(settings.theme)) {
        root.classList.add('dark');
    }
    onClose();
  };

  // --- Persist changes on Save ---
  const handleSave = () => {
    onUpdateKeys(localKeys);
    onUpdateSettings(localSettings);
    onUpdateKnownModels(localKnownModels);
    onClose();
  };

  // --- Config Export/Import Logic ---
  const handleExportSettings = () => {
    // Ensure knownModels is not included in the export (it's a cache)
    const settingsToExport = { ...localSettings };
    // @ts-ignore - Handle legacy property if present during runtime
    if (settingsToExport.knownModels) delete settingsToExport.knownModels;

    const data = {
      version: 4,
      type: 'omnichat_settings',
      timestamp: new Date().toISOString(),
      keys: localKeys,
      settings: settingsToExport
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `omnichat_config_${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    onShowToast(t('msg.config_exported', lang), 'success');
  };

  const handleImportTrigger = () => {
    fileInputRef.current?.click();
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);
        if (parsed.type === 'omnichat_settings') {
           if (parsed.keys && Array.isArray(parsed.keys)) setLocalKeys(parsed.keys);
           if (parsed.settings) {
               // Filter out knownModels if present in imported file to enforce cache-only behavior
               const importedSettings = { ...parsed.settings };
               if (importedSettings.knownModels) delete importedSettings.knownModels;
               setLocalSettings({ ...localSettings, ...importedSettings });
           }
           onShowToast(t('success.settings_import', lang), 'success');
        } else {
           onShowToast(t('msg.invalid_format', lang), 'error');
        }
      } catch (err) {
        console.error(err);
        onShowToast(t('error.load_file', lang), 'error');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  if (!isOpen) return null;

  // --- Tab Configurations ---
  const tabs = [
    { id: 'general', icon: <Sliders className="w-4 h-4"/>, label: t('settings.general', lang) },
    { id: 'apikeys', icon: <Key className="w-4 h-4"/>, label: t('settings.api_keys', lang) },
    { id: 'model', icon: <RotateCw className="w-4 h-4"/>, label: t('settings.ai_parameters', lang) },
